import type { PageData } from "./types";

export const mobsPages: PageData[] = [
  { slug: "golem-cuivre", keyword: "golem de cuivre minecraft", title: "Golem de Cuivre Minecraft : Guide Complet", h1: "Le Golem de Cuivre dans Minecraft", metaDescription: "Tout savoir sur le golem de cuivre Minecraft. Craft, comportement, oxydation et comment l'utiliser dans vos constructions.", category: "mobs", volume: 1900, content: { intro: "Le golem de cuivre est une cr\u00e9ature constructible ajout\u00e9e dans Minecraft qui interagit avec les boutons en cuivre \u00e0 proximit\u00e9. Il poss\u00e8de 20 PV (10 c\u0153urs) et s'oxyde progressivement avec le temps, comme les blocs de cuivre, finissant par se figer compl\u00e8tement en statue d\u00e9corative. C'est un ajout \u00e0 la fois d\u00e9coratif et fonctionnel pour vos bases Redstone.", sections: [{ heading: "Comment cr\u00e9er un golem de cuivre", content: "Pour construire un golem de cuivre, placez un bloc de cuivre cir\u00e9 puis une t\u00eate de cuivre par-dessus. Le golem prend vie imm\u00e9diatement et commence \u00e0 se d\u00e9placer. Il est petit, environ de la taille d'un b\u00e9b\u00e9 villageois (0,85 bloc de haut), et se d\u00e9place lentement en cherchant des boutons en cuivre \u00e0 proximit\u00e9 pour appuyer dessus." }, { heading: "Caract\u00e9ristiques et statistiques", content: "Le golem de cuivre poss\u00e8de 20 PV (10 c\u0153urs). C'est une cr\u00e9ature passive qui n'attaque jamais le joueur ni les autres mobs. Il se prom\u00e8ne librement et interagit exclusivement avec les boutons en cuivre. Comme les blocs de cuivre, il passe par 4 stades d'oxydation : normal (orange), expos\u00e9, alt\u00e9r\u00e9 et oxyd\u00e9 (vert). Une fois compl\u00e8tement oxyd\u00e9, il se fige et devient une statue immobile." }, { heading: "Cirage et entretien", content: "Utilisez un rayon de miel sur le golem pour le cirer et stopper l'oxydation \u00e0 son stade actuel. Une hache retire la cire et un niveau d'oxydation. Pour garder votre golem actif ind\u00e9finiment, cirez-le d\u00e8s sa cr\u00e9ation. Les golems compl\u00e8tement oxyd\u00e9s et fig\u00e9s constituent d'excellents \u00e9l\u00e9ments d\u00e9coratifs pour vos constructions." }, { heading: "Utilisations en Redstone", content: "Les golems de cuivre qui appuient sur des boutons en cuivre g\u00e9n\u00e8rent un signal Redstone al\u00e9atoire. Cette m\u00e9canique est id\u00e9ale pour les syst\u00e8mes de randomisation, les mini-jeux, les machines \u00e0 sous et tout circuit n\u00e9cessitant une source d'impr\u00e9visibilit\u00e9. Placez plusieurs boutons en cuivre et un golem pour cr\u00e9er un g\u00e9n\u00e9rateur de signaux al\u00e9atoires." }], tips: ["Le golem de cuivre a 20 PV (10 c\u0153urs) et est enti\u00e8rement passif", "Cirez-le avec du miel d\u00e8s sa cr\u00e9ation pour emp\u00eacher l'oxydation", "Les golems fig\u00e9s sont d'excellents \u00e9l\u00e9ments d\u00e9coratifs de statue", "Combinez-le avec des boutons en cuivre pour de la Redstone al\u00e9atoire", "Il mesure environ 0,85 bloc de haut, plus petit qu'un villageois adulte"], faq: [{ question: "Le golem de cuivre peut-il \u00eatre r\u00e9par\u00e9 ?", answer: "Un golem compl\u00e8tement oxyd\u00e9 peut \u00eatre r\u00e9activ\u00e9 en grattant l'oxydation avec une hache. Chaque utilisation de la hache retire un niveau d'oxydation. Il reprendra alors ses d\u00e9placements et ses interactions avec les boutons en cuivre." }, { question: "Combien de temps avant l'oxydation compl\u00e8te ?", answer: "L'oxydation compl\u00e8te prend environ 50-80 minutes de jeu en temps r\u00e9el, similaire aux blocs de cuivre. Chaque stade (expos\u00e9, alt\u00e9r\u00e9, oxyd\u00e9) dure environ 20 minutes. Le cirage avec du miel bloque le processus au stade actuel." }], relatedSlugs: ["bonhomme-de-neige", "golem", "metier-villageois", "reproduire-villageois", "apprivoiser-cheval"] } },
  { slug: "axolotl-bleu", keyword: "axolotl bleu minecraft", title: "Axolotl Bleu Minecraft : Comment le Trouver", h1: "L'Axolotl Bleu dans Minecraft", metaDescription: "L'axolotl bleu est le plus rare de Minecraft avec 1/1200 de chance. O\u00f9 le trouver, comment le reproduire et l'apprivoiser.", category: "mobs", volume: 880, content: { intro: "L'axolotl bleu est la variante la plus rare des axolotls dans Minecraft. Chaque axolotl poss\u00e8de 14 PV (7 c\u0153urs) et il existe en 5 couleurs : rose (lucy), brun, jaune, cyan et bleu. La variante bleue n'appara\u00eet que par reproduction avec seulement 1 chance sur 1200 (0,083%). Sa couleur indigo unique en fait un troph\u00e9e tr\u00e8s convoit\u00e9.", sections: [{ heading: "Raret\u00e9 et probabilit\u00e9", content: "L'axolotl bleu ne spawne pas naturellement dans le monde. La seule fa\u00e7on de l'obtenir est par reproduction : quand deux axolotls de n'importe quelle couleur se reproduisent, le b\u00e9b\u00e9 a exactement 1/1200 (0,083%) de chance d'\u00eatre bleu. Il faut statistiquement 1200 reproductions pour en obtenir un. Les 4 autres variantes (lucy, brun, jaune, cyan) ont chacune environ 24,98% de chance." }, { heading: "O\u00f9 trouver des axolotls", content: "Les axolotls apparaissent exclusivement dans les grottes luxuriantes (lush caves), dans les poches d'eau au-dessus de blocs d'argile. Pour localiser une grotte luxuriante, cherchez des azal\u00e9es en surface : elles indiquent une grotte luxuriante en dessous. Capturez les axolotls avec un seau d'eau (clic droit). Ils ne spawnt qu'\u00e0 un niveau de lumi\u00e8re de 0 et sous Y=63." }, { heading: "Reproduction des axolotls", content: "Nourrissez deux axolotls avec des seaux de poissons tropicaux pour les faire se reproduire. C'est le seul aliment accept\u00e9. Construisez un grand bassin de reproduction avec plusieurs paires et automatisez la distribution de poissons tropicaux. Le d\u00e9lai de reproduction est de 5 minutes entre chaque port\u00e9e. Avec de la patience et beaucoup de paires, vous maximiserez vos chances." }, { heading: "Capacit\u00e9s de combat des axolotls", content: "Les axolotls (14 PV, 2 d\u00e9g\u00e2ts en Normal) attaquent automatiquement les mobs aquatiques hostiles : gardiens, grands gardiens, noy\u00e9s, poissons-globes et poulpes. Rel\u00e2cher des axolotls dans un monument sous-marin les rend tr\u00e8s utiles contre les gardiens. Quand un axolotl tue un mob, le joueur re\u00e7oit R\u00e9g\u00e9n\u00e9ration I pendant 100 ticks. L'axolotl bleu fonctionne exactement comme les autres variantes en combat." }], tips: ["L'axolotl bleu n'appara\u00eet que par reproduction (1/1200 de chance exactement)", "Tous les axolotls ont 14 PV (7 c\u0153urs) et infligent 2 d\u00e9g\u00e2ts", "Les seaux de poissons tropicaux sont l'unique nourriture pour la reproduction", "Construisez un grand bassin avec de nombreuses paires pour maximiser les chances", "Tuer un mob via un axolotl accorde R\u00e9g\u00e9n\u00e9ration I au joueur"], faq: [{ question: "Peut-on trouver un axolotl bleu naturellement ?", answer: "Non, l'axolotl bleu ne spawne jamais naturellement dans les grottes luxuriantes ou ailleurs. Il ne peut \u00eatre obtenu que par reproduction entre deux axolotls de n'importe quelle couleur, avec une probabilit\u00e9 de 1/1200 par b\u00e9b\u00e9." }, { question: "L'axolotl bleu est-il plus fort que les autres ?", answer: "Non, toutes les variantes d'axolotl ont exactement les m\u00eames statistiques : 14 PV, 2 d\u00e9g\u00e2ts en difficult\u00e9 Normale. L'axolotl bleu est strictement identique aux autres en combat. Sa raret\u00e9 est purement cosm\u00e9tique." }], relatedSlugs: ["apprivoiser-chat", "apprivoiser-renard", "vache-champignon", "poisson-globe", "golem-cuivre"] } },
  { slug: "cheval-squelette", keyword: "cheval squelette minecraft", title: "Cheval Squelette Minecraft : Guide Complet", h1: "Le Cheval Squelette dans Minecraft", metaDescription: "D\u00e9couvrez le cheval squelette Minecraft. Comment le trouver, le monter et tout savoir sur ce mob rare des orages.", category: "mobs", volume: 260, content: { intro: "Le cheval squelette est l'un des mobs les plus rares de Minecraft. Il fait partie des cr\u00e9atures morts-vivantes et poss\u00e8de 15 PV (7,5 c\u0153urs). Il n'appara\u00eet que lors des orages via un pi\u00e8ge de cavaliers squelettes. Une fois le pi\u00e8ge d\u00e9clench\u00e9 et les squelettes vaincus, les chevaux squelettes sont automatiquement apprivois\u00e9s et constituent des montures uniques capables de galoper sous l'eau.", sections: [{ heading: "Le pi\u00e8ge du cheval squelette", content: "Pendant un orage, un cheval squelette-pi\u00e8ge peut appara\u00eetre naturellement. Quand un joueur s'approche \u00e0 moins de 10 blocs, la foudre frappe le cheval et le transforme en 4 cavaliers squelettes \u00e9quip\u00e9s d'arcs enchant\u00e9s, mont\u00e9s sur des chevaux squelettes. La probabilit\u00e9 d'apparition du pi\u00e8ge est de 0,75% \u00e0 6,75% par \u00e9clair de foudre, selon la difficult\u00e9 r\u00e9gionale. Tuez les squelettes cavaliers pour r\u00e9cup\u00e9rer les chevaux." }, { heading: "Monter un cheval squelette", content: "Apr\u00e8s avoir \u00e9limin\u00e9 les squelettes cavaliers, les chevaux squelettes sont automatiquement apprivois\u00e9s et montables. Vous pouvez les \u00e9quiper d'une selle pour les contr\u00f4ler. Les chevaux squelettes ne peuvent PAS porter d'armure de cheval. En tant que cr\u00e9ature mort-vivante, le cheval squelette est immunis\u00e9 contre la noyade et peut galoper sous l'eau \u00e0 pleine vitesse, ce qui en fait une monture aquatique id\u00e9ale." }, { heading: "Caract\u00e9ristiques et statistiques", content: "Le cheval squelette poss\u00e8de 15 PV (7,5 c\u0153urs). Sa vitesse et sa hauteur de saut sont g\u00e9n\u00e9r\u00e9es al\u00e9atoirement comme pour les chevaux normaux. En tant que mort-vivant, il br\u00fble au soleil dans l'\u00e9dition Bedrock (pas en Java). Il ne peut pas \u00eatre nourri, soign\u00e9 avec de la nourriture, ni se reproduire. Il ne peut pas non plus porter de coffre comme un \u00e2ne." }], tips: ["Le cheval squelette est une cr\u00e9ature mort-vivante avec 15 PV (7,5 c\u0153urs)", "Le pi\u00e8ge n'appara\u00eet que pendant les orages (0,75-6,75% par \u00e9clair)", "Approchez-vous \u00e0 moins de 10 blocs pour d\u00e9clencher le pi\u00e8ge des 4 cavaliers", "Le cheval squelette peut galoper sous l'eau sans ralentir (immunis\u00e9 \u00e0 la noyade)", "Il est automatiquement apprivois\u00e9 apr\u00e8s avoir tu\u00e9 le squelette cavalier"], faq: [{ question: "Le cheval squelette peut-il mourir de faim ?", answer: "Non, le cheval squelette ne mange pas et ne peut pas mourir de faim. En tant que cr\u00e9ature mort-vivante, il est immunis\u00e9 \u00e0 la noyade et \u00e0 l'empoisonnement. Il ne peut pas \u00eatre soign\u00e9 avec de la nourriture, uniquement avec une potion de d\u00e9g\u00e2ts (m\u00e9canique des morts-vivants)." }, { question: "Peut-on reproduire les chevaux squelettes ?", answer: "Non, les chevaux squelettes ne peuvent pas se reproduire. La seule fa\u00e7on d'en obtenir est via le pi\u00e8ge de l'orage. De m\u00eame, ils ne peuvent pas \u00eatre crois\u00e9s avec des chevaux normaux ou des \u00e2nes." }], relatedSlugs: ["apprivoiser-cheval", "reproduire-chevaux", "golem-cuivre", "bonhomme-de-neige", "axolotl-bleu"] } },
  { slug: "bonhomme-de-neige", keyword: "bonhomme de neige minecraft", title: "Bonhomme de Neige Minecraft : Cr\u00e9ation", h1: "Comment Cr\u00e9er un Bonhomme de Neige dans Minecraft", metaDescription: "Cr\u00e9ez un bonhomme de neige Minecraft avec des blocs de neige et une citrouille. Comportement, utilit\u00e9 et astuces d\u00e9taill\u00e9s.", category: "mobs", volume: 260, content: { intro: "Le bonhomme de neige (golem de neige) est une cr\u00e9ature constructible dans Minecraft poss\u00e9dant 4 PV (2 c\u0153urs). Il lance des boules de neige sur les mobs hostiles \u00e0 port\u00e9e et laisse une tra\u00een\u00e9e de neige au sol. Bien que ses boules de neige ne fassent g\u00e9n\u00e9ralement pas de d\u00e9g\u00e2ts, elles sont redoutables contre les Blazes (3 d\u00e9g\u00e2ts par boule). C'est un alli\u00e9 d\u00e9fensif utile et une source de neige renouvelable.", sections: [{ heading: "Construction du golem de neige", content: "Empilez 2 blocs de neige verticalement, puis placez une citrouille sculpt\u00e9e (ou une citrouille normale dans l'\u00e9dition Bedrock) sur le dessus. Le bonhomme de neige prend vie imm\u00e9diatement. Les blocs de neige se craftent avec 4 boules de neige chacun (2x2). La citrouille sculpt\u00e9e s'obtient en utilisant des cisailles sur une citrouille. L'ordre de placement est important : les blocs de neige d'abord, la citrouille en dernier." }, { heading: "Comportement et combat", content: "Le golem de neige (4 PV, 2 c\u0153urs) lance des boules de neige sur tous les mobs hostiles dans un rayon de 10 blocs. Les boules de neige infligent 0 d\u00e9g\u00e2t \u00e0 la plupart des mobs (mais les repoussent avec du knockback), SAUF aux Blazes qui subissent 3 d\u00e9g\u00e2ts par boule de neige. Il ne cible jamais les creepers. Il laisse une couche de neige au sol dans les biomes froids et temp\u00e9r\u00e9s, mais pas dans les biomes chauds." }, { heading: "Faiblesses et limitations", content: "Le golem de neige est tr\u00e8s fragile avec seulement 4 PV. Il prend des d\u00e9g\u00e2ts dans les biomes chauds (d\u00e9sert, badlands, jungle, savane) et dans le Nether, o\u00f9 il fond rapidement. La pluie lui inflige \u00e9galement des d\u00e9g\u00e2ts. Prot\u00e9gez-le avec un toit contre la pluie et ne l'emmenez jamais dans des biomes chauds." }, { heading: "Utilisations pratiques", content: "Ferme \u00e0 neige : enfermez un golem dans un enclos de 2x2 et r\u00e9coltez la neige qu'il laisse au sol avec une pelle. D\u00e9fense de base : placez-en plusieurs derri\u00e8re des murs pour repousser les mobs hostiles avec le knockback. Contre les Blazes : emmenez des golems dans le Nether (ils fondront mais pourront tuer plusieurs Blazes avant). Chaque boule de neige inflige 3 d\u00e9g\u00e2ts aux Blazes." }], tips: ["Le golem de neige n'a que 4 PV (2 c\u0153urs), c'est le mob constructible le plus fragile", "Ses boules de neige font 3 d\u00e9g\u00e2ts aux Blazes mais 0 aux autres mobs", "Il laisse une tra\u00een\u00e9e de neige r\u00e9coltable dans les biomes froids et temp\u00e9r\u00e9s", "Il meurt rapidement dans les biomes chauds (d\u00e9sert, jungle, savane, Nether)", "Placez un toit au-dessus pour le prot\u00e9ger de la pluie qui lui inflige des d\u00e9g\u00e2ts"], faq: [{ question: "Le bonhomme de neige survit-il dans le Nether ?", answer: "Non, il prend des d\u00e9g\u00e2ts de chaleur constants dans le Nether et fond en quelques secondes. Il r\u00e9agit de m\u00eame dans les d\u00e9serts, jungles, badlands et savanes. Gardez-le exclusivement dans des biomes froids ou temp\u00e9r\u00e9s, \u00e0 l'abri de la pluie." }, { question: "Peut-on lui enlever sa citrouille ?", answer: "Oui, utilisez des cisailles (clic droit) sur le bonhomme de neige pour retirer sa citrouille et r\u00e9v\u00e9ler sa t\u00eate de neige avec des yeux et un sourire. C'est purement cosm\u00e9tique et ne change pas ses statistiques." }], relatedSlugs: ["golem-cuivre", "golem", "apprivoiser-cheval", "metier-villageois", "cheval-squelette"] } },
  { slug: "apprivoiser-cheval", keyword: "comment apprivoiser un cheval dans minecraft", title: "Apprivoiser un Cheval Minecraft : Guide", h1: "Comment Apprivoiser un Cheval dans Minecraft", metaDescription: "Apprivoisez un cheval dans Minecraft en le montant plusieurs fois. Selle, armure et comment choisir le meilleur cheval.", category: "mobs", volume: 320, content: { intro: "Les chevaux sont des mobs passifs qui apparaissent dans les biomes de plaines et de savane par groupes de 2 \u00e0 6. Chaque cheval poss\u00e8de entre 15 et 30 PV (7,5 \u00e0 15 c\u0153urs), une vitesse variant de 4,74 \u00e0 14,23 blocs/s et un saut de 1,09 \u00e0 5,29 blocs de haut. Les apprivoiser est simple mais choisir le meilleur cheval demande de tester ses statistiques.", sections: [{ heading: "Apprivoiser un cheval", content: "Approchez-vous d'un cheval sauvage et montez-le \u00e0 main vide (clic droit). Le cheval va vous \u00e9jecter. Remontez \u00e0 chaque fois jusqu'\u00e0 ce que des c\u0153urs apparaissent, signalant l'apprivoisement. Chaque tentative a une chance cumulative de r\u00e9ussir, bas\u00e9e sur le \u00ab temper \u00bb du cheval (0 \u00e0 100). Nourrir le cheval avec du sucre (+3), du bl\u00e9 (+3), des pommes (+3), des pommes dor\u00e9es (+10) ou des carottes dor\u00e9es (+5) augmente le temper et acc\u00e9l\u00e8re l'apprivoisement." }, { heading: "\u00c9quiper le cheval", content: "Une fois apprivois\u00e9, ouvrez l'inventaire du cheval (montez puis appuyez sur E, ou Shift+clic droit). Placez une selle dans l'emplacement d\u00e9di\u00e9 pour pouvoir le diriger. Ajoutez une armure de cheval (en cuir, fer, or ou diamant) pour augmenter sa protection. Les armures de cheval en diamant offrent 11 points d'armure. Les selles ne se craftent pas : elles se trouvent dans les coffres de donjons, forteresses, temples et villages." }, { heading: "Statistiques et s\u00e9lection", content: "Chaque cheval g\u00e9n\u00e8re al\u00e9atoirement 3 statistiques ind\u00e9pendantes : sant\u00e9 (15-30 PV), vitesse (4,74-14,23 blocs/s) et hauteur de saut (1,09-5,29 blocs). Les statistiques ne sont pas li\u00e9es \u00e0 la robe du cheval. Pour tester la vitesse, chronom\u00e9trez un cheval sur une piste de 100 blocs. Pour le saut, testez-le sur des obstacles de hauteur croissante. Les meilleurs chevaux combinent haute vitesse et bon saut." }, { heading: "O\u00f9 trouver des chevaux", content: "Les chevaux spawnt naturellement dans les biomes de plaines et de savane, en troupeaux de 2 \u00e0 6. Ils existent en 7 couleurs de robe et 5 motifs de marquage, pour 35 combinaisons visuelles possibles. Les villages de plaines poss\u00e8dent parfois des enclos avec des chevaux pr\u00e9-spawn\u00e9s. Les \u00e2nes se trouvent dans les m\u00eames biomes et peuvent \u00eatre crois\u00e9s avec les chevaux pour obtenir des mules." }], tips: ["Les chevaux ont entre 15 et 30 PV et une vitesse de 4,74 \u00e0 14,23 blocs/s", "Nourrissez le cheval avec une pomme dor\u00e9e (+10 temper) pour acc\u00e9l\u00e9rer l'apprivoisement", "Les selles ne se craftent pas : trouvez-les dans les coffres ou chez un tanneur villageois", "Testez la vitesse et le saut de chaque cheval avant de choisir votre monture", "Les armures de cheval en diamant offrent la meilleure protection (11 points d'armure)"], faq: [{ question: "O\u00f9 trouver des selles ?", answer: "Les selles se trouvent dans les coffres des donjons, forteresses du Nether, temples du d\u00e9sert, temples de la jungle, villages (maison du tanneur), bastions et anciennes cit\u00e9s. Les villageois tanneurs de niveau ma\u00eetre en vendent pour 6 \u00e9meraudes. La p\u00eache avec Chance de la Mer III peut aussi en donner." }, { question: "Peut-on mettre une armure sur un \u00e2ne ?", answer: "Non, les \u00e2nes et les mules ne peuvent pas porter d'armure de cheval. En revanche, ils peuvent porter un coffre (clic droit avec un coffre), ce qui ajoute 15 emplacements d'inventaire et les rend utiles pour le transport d'objets lors d'exp\u00e9ditions." }], relatedSlugs: ["reproduire-chevaux", "cheval-squelette", "apprivoiser-chat", "apprivoiser-renard", "metier-villageois"] } },
  { slug: "apprivoiser-chat", keyword: "comment apprivoiser un chat sur minecraft", title: "Apprivoiser un Chat Minecraft : Guide", h1: "Comment Apprivoiser un Chat dans Minecraft", metaDescription: "Apprivoisez un chat Minecraft avec du poisson cru. Les chats font fuir les creepers et les phantoms. Guide complet.", category: "mobs", volume: 170, content: { intro: "Les chats sont des mobs passifs apprivoisables dans Minecraft poss\u00e9dant 10 PV (5 c\u0153urs). Ils apparaissent dans les villages (1 chat pour 4 lits, maximum 10 par village) et dans les cabanes de sorci\u00e8res (1 chat noir). Une fois apprivois\u00e9s, ils font fuir les creepers et les phantoms dans un rayon de 6 blocs, ce qui en fait d'excellents protecteurs pour votre base.", sections: [{ heading: "Trouver et apprivoiser un chat", content: "Les chats errants spawnt dans les villages ayant au moins 1 villageois et 4 lits. Approchez-vous lentement avec du poisson cru (morue crue ou saumon cru) en main. Ne faites aucun mouvement brusque : si vous bougez trop vite ou tournez la t\u00eate rapidement, le chat fuira. Attendez immobile que le chat s'approche de lui-m\u00eame, puis nourrissez-le. Chaque poisson a 33% de chance d'apprivoiser le chat (1/3). Il faut donc en moyenne 2 \u00e0 5 poissons." }, { heading: "Capacit\u00e9s d\u00e9fensives", content: "Les creepers et les phantoms fuient activement les chats dans un rayon de 6 blocs. Gardez un chat apprivois\u00e9 pr\u00e8s de votre lit pour emp\u00eacher les phantoms de vous attaquer la nuit. Placez plusieurs chats autour de votre base pour cr\u00e9er une zone anti-creeper. Cette capacit\u00e9 fonctionne que le chat soit assis ou debout, c'est l'un des m\u00e9canismes d\u00e9fensifs les plus utiles du jeu." }, { heading: "Vari\u00e9t\u00e9s et cadeaux nocturnes", content: "Il existe 11 vari\u00e9t\u00e9s de chats avec des pelages diff\u00e9rents : tabby, tuxedo, roux, siamois, british shorthair, calico, persan, ragdoll, blanc, noir et jellie. Le chat noir ne spawne naturellement que dans les cabanes de sorci\u00e8res. Quand vous dormez avec un chat apprivois\u00e9 \u00e0 proximit\u00e9, il a une chance de vous offrir un cadeau au r\u00e9veil : ficelle, plume, poulet cru, chair putr\u00e9fi\u00e9e, patte de lapin ou peau de lapin." }, { heading: "Reproduction", content: "Les chats apprivois\u00e9s se reproduisent avec de la morue crue ou du saumon cru. Le b\u00e9b\u00e9 chat h\u00e9rite al\u00e9atoirement du pelage de l'un des deux parents. Les b\u00e9b\u00e9s chats grandissent en 20 minutes, acc\u00e9l\u00e9rable avec du poisson cru. La reproduction a un d\u00e9lai de 5 minutes entre chaque port\u00e9e." }], tips: ["Les chats ont 10 PV (5 c\u0153urs) et une chance d'apprivoisement de 33% par poisson", "Les creepers et phantoms fuient les chats dans un rayon de 6 blocs", "Ne bougez pas quand vous essayez d'apprivoiser un chat, il fuira sinon", "La morue crue et le saumon cru sont les seules nourritures accept\u00e9es", "Les chats offrent des cadeaux al\u00e9atoires quand vous dormez \u00e0 c\u00f4t\u00e9 d'eux"], faq: [{ question: "Mon chat peut-il mourir ?", answer: "Oui, les chats apprivois\u00e9s ont 10 PV (5 c\u0153urs) et peuvent \u00eatre tu\u00e9s par les mobs hostiles, les chutes, la lave et d'autres sources de d\u00e9g\u00e2ts. Cependant, les chats sont immunis\u00e9s aux d\u00e9g\u00e2ts de chute (ils retombent toujours sur leurs pattes sans d\u00e9g\u00e2t). Gardez-les \u00e0 l'abri de la lave et des mobs." }, { question: "Les chats restent-ils assis quand je pars ?", answer: "Un chat assis (clic droit) ne bouge pas et ne vous suit pas, m\u00eame si vous partez tr\u00e8s loin. Un chat debout vous suit partout et se t\u00e9l\u00e9porte \u00e0 vous si vous \u00eates \u00e0 plus de 12 blocs. Asseyez-le pour le garder \u00e0 la maison en s\u00e9curit\u00e9." }], relatedSlugs: ["apprivoiser-cheval", "apprivoiser-renard", "apprivoiser-perroquet", "metier-villageois", "axolotl-bleu"] } },
  { slug: "apprivoiser-renard", keyword: "comment apprivoiser un renard dans minecraft", title: "Apprivoiser un Renard Minecraft : Guide", h1: "Comment Apprivoiser un Renard dans Minecraft", metaDescription: "Apprivoisez un renard Minecraft en faisant se reproduire deux renards sauvages. Le b\u00e9b\u00e9 renard vous fera confiance.", category: "mobs", volume: 170, content: { intro: "Les renards sont des mobs neutres nocturnes dans Minecraft poss\u00e9dant 20 PV (10 c\u0153urs). Ils spawnt dans les biomes de ta\u00efga (normale, enneig\u00e9e et de vieux sapins) par groupes de 2 \u00e0 4. Contrairement aux loups ou aux chats, les renards ne peuvent pas \u00eatre apprivois\u00e9s directement : vous devez faire reproduire deux renards sauvages et le b\u00e9b\u00e9 vous fera confiance.", sections: [{ heading: "M\u00e9thode d'apprivoisement", content: "Trouvez deux renards dans un biome de ta\u00efga la nuit (ils sont nocturnes). Approchez-vous furtivement (en vous accroupissant) car les renards fuient les joueurs \u00e0 12 blocs de distance. Nourrissez chacun avec des baies sucr\u00e9es (sweet berries) pour les faire se reproduire. Le b\u00e9b\u00e9 renard fera imm\u00e9diatement confiance au joueur qui a nourri les parents. Attachez le b\u00e9b\u00e9 avec une laisse et \u00e9loignez-le de ses parents. Une fois loin, il vous suivra fid\u00e8lement." }, { heading: "Comportement et capacit\u00e9s", content: "Les renards (20 PV, 2 d\u00e9g\u00e2ts en Normal) sont des cr\u00e9atures nocturnes qui dorment le jour en se roulant en boule. Ils attaquent les poulets, les lapins, les morues, les saumons et les poissons tropicaux. Un renard de confiance ne vous fuira pas mais ne peut pas recevoir d'ordres comme un loup. Il attaquera les mobs qui vous blessent. Sa capacit\u00e9 unique : il peut ramasser n'importe quel objet au sol dans sa gueule et l'utiliser si c'est une arme." }, { heading: "Renard roux et renard arctique", content: "Les renards roux spawnt dans les ta\u00efgas normales et de vieux sapins. Les renards arctiques (blancs) spawnt dans les ta\u00efgas enneig\u00e9es. Ils ont exactement les m\u00eames statistiques et comportements. Si vous croisez un renard roux et un arctique, le b\u00e9b\u00e9 a 50% de chance d'\u00eatre de l'une ou l'autre couleur. Les deux variantes sont purement cosm\u00e9tiques." }], tips: ["Les renards ont 20 PV (10 c\u0153urs) et infligent 2 d\u00e9g\u00e2ts en difficult\u00e9 Normale", "Les baies sucr\u00e9es sont l'unique nourriture pour la reproduction", "Approchez-vous accroupi car les renards fuient \u00e0 12 blocs de distance", "Le b\u00e9b\u00e9 fait confiance au joueur mais ne peut pas \u00eatre command\u00e9 comme un loup", "Les renards ramassent les objets au sol et utilisent les armes enchant\u00e9es !"], faq: [{ question: "Le renard ob\u00e9it-il comme un loup ?", answer: "Non, le renard de confiance ne peut pas s'asseoir ni suivre des ordres. Il vous fait confiance (ne vous fuit pas), vous suit naturellement quand il est \u00e9loign\u00e9 de ses parents, et attaquera les mobs qui vous blessent. Mais il n'a pas le syst\u00e8me d'ordres du loup apprivois\u00e9." }, { question: "Le renard peut-il tenir des objets ?", answer: "Oui, les renards ramassent automatiquement les objets au sol dans leur gueule. Si un renard ramasse une \u00e9p\u00e9e enchant\u00e9e Tranchant V, il infligera les d\u00e9g\u00e2ts de l'enchantement en combat ! Vous pouvez aussi lui donner un objet en le laissant tomber devant lui. Il l\u00e2che l'objet pr\u00e9c\u00e9dent pour ramasser le nouveau." }], relatedSlugs: ["apprivoiser-chat", "apprivoiser-cheval", "apprivoiser-perroquet", "metier-villageois", "axolotl-bleu"] } },
  { slug: "apprivoiser-perroquet", keyword: "comment apprivoiser un perroquet dans minecraft", title: "Apprivoiser un Perroquet Minecraft : Guide", h1: "Comment Apprivoiser un Perroquet dans Minecraft", metaDescription: "Apprivoisez un perroquet Minecraft avec des graines. 5 couleurs, imitation de mobs et perroquet sur l'\u00e9paule. Guide complet.", category: "mobs", volume: 110, content: { intro: "Les perroquets sont des mobs passifs rares de la jungle dans Minecraft poss\u00e9dant seulement 6 PV (3 c\u0153urs). Ils existent en 5 couleurs (rouge, bleu, vert, cyan et gris) et imitent les sons des mobs proches, servant de syst\u00e8me d'alerte naturel. Ils peuvent se percher sur vos \u00e9paules lors de vos aventures.", sections: [{ heading: "Apprivoisement avec des graines", content: "Les perroquets spawnt uniquement dans les biomes de jungle (normale et bambou). Ils sont rares et ne spawnt que sur les blocs de bois ou de feuilles au-dessus de Y=70. Nourrissez-les avec n'importe quelle graine : graines de bl\u00e9, de melon, de citrouille, de betterave ou de tournesol. Chaque graine a 33% de chance (1/3) d'apprivoiser le perroquet. ATTENTION : ne donnez JAMAIS de cookie \u00e0 un perroquet, c'est toxique et le tue instantan\u00e9ment." }, { heading: "Perroquet sur l'\u00e9paule", content: "Approchez-vous d'un perroquet apprivois\u00e9 au sol et il sautera sur votre \u00e9paule. Vous pouvez en avoir un sur chaque \u00e9paule (maximum 2). Le perroquet descend quand vous sautez, tombez d'un bloc, vous accroupissez, entrez dans l'eau ou dormez dans un lit. Il continue d'imiter les sons des mobs m\u00eame sur votre \u00e9paule, ce qui en fait un radar mobile." }, { heading: "Syst\u00e8me d'alerte sonore", content: "Les perroquets d\u00e9tectent les mobs hostiles dans un rayon de 20 blocs et imitent leurs sons en version plus aigu\u00eb. Si votre perroquet \u00e9met le sifflement d'un creeper, c'est qu'un creeper se trouve \u00e0 moins de 20 blocs. Ils imitent les sons des zombies, squelettes, creepers, araign\u00e9es, endermen et autres mobs hostiles. C'est un syst\u00e8me d'alerte extr\u00eamement utile en exploration souterraine." }, { heading: "Danse et comportement", content: "Les perroquets dansent quand un jukebox joue de la musique \u00e0 proximit\u00e9. C'est un comportement purement cosm\u00e9tique mais tr\u00e8s amusant. Ils se t\u00e9l\u00e9portent au joueur s'ils sont trop \u00e9loign\u00e9s (comme les loups et chats apprivois\u00e9s). Avec seulement 6 PV, ils sont tr\u00e8s fragiles : prot\u00e9gez-les des mobs hostiles et des chutes." }], tips: ["Les perroquets n'ont que 6 PV (3 c\u0153urs), prot\u00e9gez-les des mobs et chutes", "N'importe quelle graine fonctionne pour l'apprivoisement (33% de chance par graine)", "Ne donnez JAMAIS de cookie \u00e0 un perroquet : c'est mortel instantan\u00e9ment", "Les perroquets imitent les sons des mobs hostiles dans un rayon de 20 blocs", "Ils dansent pr\u00e8s d'un jukebox qui joue de la musique"], faq: [{ question: "Pourquoi les cookies tuent-ils les perroquets ?", answer: "C'est une r\u00e9f\u00e9rence au fait que le chocolat (cacao) est toxique pour les oiseaux dans la r\u00e9alit\u00e9. Mojang a ajout\u00e9 cette m\u00e9canique pour sensibiliser les joueurs. Un cookie tue un perroquet instantan\u00e9ment, m\u00eame s'il a tous ses PV. Ne leur donnez que des graines." }, { question: "Peut-on faire reproduire les perroquets ?", answer: "Non, les perroquets ne peuvent pas se reproduire dans Minecraft. Il n'existe aucune nourriture de reproduction pour eux. Vous devez trouver et apprivoiser chaque perroquet individuellement dans les biomes de jungle." }], relatedSlugs: ["apprivoiser-chat", "apprivoiser-renard", "apprivoiser-cheval", "axolotl-bleu", "metier-villageois"] } },
  { slug: "reproduire-villageois", keyword: "reproduire villageois minecraft", title: "Reproduire des Villageois Minecraft : Guide", h1: "Comment Reproduire des Villageois dans Minecraft", metaDescription: "Faites se reproduire les villageois Minecraft avec des lits et de la nourriture. Conditions, astuces et ferme \u00e0 villageois.", category: "mobs", volume: 320, content: { intro: "Les villageois sont des PNJ passifs poss\u00e9dant 20 PV (10 c\u0153urs) qui vivent dans les villages. Augmenter leur population est essentiel pour acc\u00e9der \u00e0 plus d'\u00e9changes commerciaux et pour les fermes \u00e0 fer (les golems de fer spawnt naturellement dans les villages de 3+ villageois). La reproduction n\u00e9cessite des conditions pr\u00e9cises : lits libres et nourriture suffisante.", sections: [{ heading: "Conditions de reproduction", content: "Les villageois se reproduisent quand 3 conditions sont r\u00e9unies : 1) Un lit libre non-r\u00e9clam\u00e9 avec au moins 2 blocs d'espace libre au-dessus (le b\u00e9b\u00e9 doit pouvoir sauter sur le lit). 2) De la nourriture suffisante dans l'inventaire d'un villageois : 3 pains, 12 carottes, 12 pommes de terre ou 12 betteraves donnent la \u00ab volont\u00e9 \u00bb de se reproduire. 3) Les deux parents doivent \u00eatre volontaires simultan\u00e9ment. Il n'y a pas de d\u00e9lai de reproduction comme pour les animaux." }, { heading: "Donner de la nourriture", content: "Lancez de la nourriture aux pieds des villageois : pain, carottes, pommes de terre ou betteraves. Les villageois ramassent ces items et les stockent dans leur inventaire (8 emplacements). Le pain est le plus efficace : 3 pains suffisent pour rendre un villageois volontaire. Les fermiers villageois (avec un composteur) r\u00e9coltent automatiquement le bl\u00e9 et fabriquent du pain qu'ils partagent avec les autres villageois, automatisant le processus." }, { heading: "Construire une maternit\u00e9 efficace", content: "Construisez une pi\u00e8ce ferm\u00e9e avec au moins 3 lits (1 pour chaque parent + 1 pour le b\u00e9b\u00e9), bien \u00e9clair\u00e9e pour \u00e9viter les spawns de mobs hostiles. Enfermez 2 villageois avec beaucoup de nourriture et des lits exc\u00e9dentaires. Ils se reproduiront tant qu'il y a des lits non-r\u00e9clam\u00e9s accessibles. Les b\u00e9b\u00e9s villageois grandissent en exactement 20 minutes de jeu." }, { heading: "Ferme \u00e0 villageois automatique", content: "Pour une production automatis\u00e9e : placez un villageois fermier avec un composteur \u00e0 c\u00f4t\u00e9 de parcelles de bl\u00e9/carottes/pommes de terre. Le fermier r\u00e9colte, fabrique du pain et le partage avec d'autres villageois dans la zone. Ajoutez beaucoup de lits exc\u00e9dentaires. Les b\u00e9b\u00e9s peuvent \u00eatre transport\u00e9s via un canal d'eau ou un syst\u00e8me de rails vers une zone s\u00e9par\u00e9e avec des blocs de travail pr\u00e9-plac\u00e9s pour d\u00e9terminer leur futur m\u00e9tier." }], tips: ["Les villageois ont 20 PV (10 c\u0153urs) et sont class\u00e9s comme PNJ passifs", "Chaque lit exc\u00e9dentaire libre permet la naissance d'un nouveau villageois", "Le pain est la nourriture la plus efficace : 3 pains par villageois suffisent", "Les b\u00e9b\u00e9s villageois grandissent en exactement 20 minutes de jeu", "Un fermier villageois automatise la distribution de nourriture en r\u00e9coltant et partageant"], faq: [{ question: "Pourquoi mes villageois ne se reproduisent-ils pas ?", answer: "V\u00e9rifiez ces points dans l'ordre : 1) Il faut au moins 1 lit libre non-r\u00e9clam\u00e9 avec 2 blocs d'espace au-dessus. 2) Les villageois doivent avoir assez de nourriture (lancez au moins 6 pains par villageois). 3) Aucune menace \u00e0 proximit\u00e9 (les zombies d\u00e9clenchent un \u00e9tat de panique qui bloque la reproduction). 4) Assurez-vous que les villageois peuvent atteindre les lits." }, { question: "Les b\u00e9b\u00e9s villageois prennent-ils un m\u00e9tier ?", answer: "Les b\u00e9b\u00e9s n'ont pas de m\u00e9tier et ne peuvent pas commercer. En grandissant (apr\u00e8s 20 minutes), ils cherchent un bloc de travail non-r\u00e9clam\u00e9 \u00e0 proximit\u00e9 pour prendre un m\u00e9tier. Vous pouvez influencer leur profession en pla\u00e7ant le bloc de travail souhait\u00e9 dans leur zone avant qu'ils ne grandissent." }], relatedSlugs: ["metier-villageois", "echange-villageois", "bebe-villageois", "trouver-village", "apprivoiser-cheval"] } },
  { slug: "metier-villageois", keyword: "metier villageois minecraft", title: "M\u00e9tiers des Villageois Minecraft : Guide Complet", h1: "Tous les M\u00e9tiers des Villageois dans Minecraft", metaDescription: "Guide complet des 13 m\u00e9tiers de villageois Minecraft. Blocs de travail, \u00e9changes et comment changer le m\u00e9tier d'un villageois.", category: "mobs", volume: 1300, content: { intro: "Les villageois de Minecraft (20 PV, passifs) ont 13 m\u00e9tiers possibles, chacun associ\u00e9 \u00e0 un bloc de t\u00e2che sp\u00e9cifique. Les villageois apparaissent dans les villages de 7 biomes diff\u00e9rents (plaines, d\u00e9sert, savane, ta\u00efga, neige, jungle, marais) avec des v\u00eatements adapt\u00e9s \u00e0 leur biome et leur profession. Comprendre les m\u00e9tiers est crucial pour obtenir les meilleurs \u00e9changes commerciaux.", sections: [{ heading: "Liste compl\u00e8te des 13 m\u00e9tiers et blocs de t\u00e2che", content: "Voici les 13 professions et leur bloc de t\u00e2che associ\u00e9 : Armurier (haut fourneau), Berger (m\u00e9tier \u00e0 tisser), Biblioth\u00e9caire (pupitre), Boucher (fumoir), Cartographe (table de cartographie), Fermier (composteur), Fl\u00e9chier (table d'archerie), Forgeron d'armes (meule), Forgeron d'outils (table de forgeron), Ma\u00e7on (tailleur de pierre), P\u00eacheur (tonneau), Pr\u00eatre (alambic), Tanneur (chaudron). Deux types sp\u00e9ciaux ne commercent pas : le villageois sans profession (pas de bloc) et l'idiot/nitwit (v\u00eatements verts, ne prend jamais de m\u00e9tier)." }, { heading: "Meilleurs m\u00e9tiers pour le joueur", content: "Le biblioth\u00e9caire (pupitre) est le villageois le plus utile : il vend des livres enchant\u00e9s, dont Raccommodage, Fortune III, Protection IV et Efficacit\u00e9 V. Le fermier (composteur) ach\u00e8te vos r\u00e9coltes contre des \u00e9meraudes facilement. Le ma\u00e7on (tailleur de pierre) ach\u00e8te la pierre et vend du quartz et de la terre cuite \u00e9maill\u00e9e. L'armurier (haut fourneau) vend l'armure en diamant enchant\u00e9e au niveau Ma\u00eetre. Le forgeron d'outils (table de forgeron) vend des pioches et haches en diamant enchant\u00e9es." }, { heading: "Changer le m\u00e9tier d'un villageois", content: "Cassez le bloc de t\u00e2che d'un villageois pour lui retirer sa profession, puis placez un nouveau bloc de t\u00e2che \u00e0 proximit\u00e9. Le villageois adoptera le nouveau m\u00e9tier. IMPORTANT : cela ne fonctionne QUE si le villageois est au niveau Novice et que vous n'avez JAMAIS \u00e9chang\u00e9 avec lui. Un villageois avec qui vous avez effectu\u00e9 au moins un \u00e9change garde d\u00e9finitivement son m\u00e9tier, m\u00eame si vous cassez son bloc de t\u00e2che." }, { heading: "Syst\u00e8me de niveaux et progression", content: "Les villageois ont 5 niveaux de progression : Novice (badge en pierre), Apprenti (badge en fer), Compagnon (badge en or), Expert (badge en \u00e9meraude), Ma\u00eetre (badge en diamant). Chaque \u00e9change accorde de l'XP au villageois. De meilleurs \u00e9changes se d\u00e9bloquent \u00e0 chaque niveau. Le villageois doit acc\u00e9der \u00e0 son bloc de t\u00e2che pour renouveler ses \u00e9changes (2 fois par jour maximum). Les offres de niveau Ma\u00eetre incluent les meilleurs items." }], tips: ["13 m\u00e9tiers + 2 types sp\u00e9ciaux (sans profession et idiot/nitwit)", "Le biblioth\u00e9caire est le plus utile pour Raccommodage et les enchantements rares", "Cassez et replacez le pupitre d'un biblioth\u00e9caire novice pour r\u00e9initialiser ses offres", "Un villageois avec qui vous avez \u00e9chang\u00e9 ne peut plus changer de m\u00e9tier", "Gu\u00e9rissez les villageois zombies pour des r\u00e9ductions permanentes sur tous les \u00e9changes", "L'idiot (nitwit, v\u00eatements verts) ne prendra jamais de m\u00e9tier"], faq: [{ question: "Comment obtenir Raccommodage d'un biblioth\u00e9caire ?", answer: "Placez un pupitre pr\u00e8s d'un villageois novice sans m\u00e9tier. V\u00e9rifiez ses offres de niveau Novice. Si Raccommodage n'est pas propos\u00e9, cassez le pupitre, attendez que le villageois perde son m\u00e9tier, puis replacez le pupitre. R\u00e9p\u00e9tez jusqu'\u00e0 obtenir le livre souhait\u00e9. N'\u00e9changez jamais avec lui tant que vous n'avez pas l'offre d\u00e9sir\u00e9e." }, { question: "Combien de types de villageois y a-t-il au total ?", answer: "Il y a 13 m\u00e9tiers actifs (armurier, berger, biblioth\u00e9caire, boucher, cartographe, fermier, fl\u00e9chier, forgeron d'armes, forgeron d'outils, ma\u00e7on, p\u00eacheur, pr\u00eatre, tanneur), plus le villageois sans profession (qui peut prendre un m\u00e9tier) et l'idiot/nitwit (qui ne prend jamais de m\u00e9tier). Soit 15 types au total." }], relatedSlugs: ["reproduire-villageois", "echange-villageois", "bebe-villageois", "trouver-village", "enlever-metier-villageois"] } },
  { slug: "vache-champignon", keyword: "vache champignon minecraft", title: "Vache Champignon Minecraft : Guide Complet", h1: "La Vache Champignon dans Minecraft", metaDescription: "Trouvez la vache champignon Minecraft dans le biome champignon. Soupe suspecte, tonte et reproduction de ce mob rare.", category: "mobs", volume: 170, content: { intro: "La vache champignon (mooshroom) est une variante rare de la vache poss\u00e9dant 10 PV (5 c\u0153urs) qui vit exclusivement dans le biome \u00eele aux champignons. Elle peut \u00eatre traite avec un bol pour obtenir un rago\u00fbt de champignon gratuit et infini, ou taill\u00e9e avec des cisailles pour la transformer en vache normale. C'est l'un des mobs les plus utiles pour l'alimentation.", sections: [{ heading: "O\u00f9 trouver les vaches champignon", content: "Les mooshrooms spawnt exclusivement dans le biome \u00eele aux champignons (mushroom fields), l'un des biomes les plus rares du jeu. Ce biome est reconnaissable \u00e0 son sol de myc\u00e9lium et ses champignons g\u00e9ants. Il se g\u00e9n\u00e8re comme une \u00eele isol\u00e9e dans l'oc\u00e9an. Aucun mob hostile ne spawne naturellement dans ce biome, ce qui en fait un lieu s\u00fbr. Les mooshrooms spawnt par groupes de 4 \u00e0 8." }, { heading: "Utilisations uniques", content: "Traite avec un bol vide (clic droit) : donne un rago\u00fbt de champignon (6 points de faim, 7,2 saturation), utilisable \u00e0 l'infini. Nourrissez-la avec une petite fleur AVANT de la traire avec un bol pour obtenir une soupe suspecte aux effets sp\u00e9ciaux selon la fleur : p\u00e2querette (r\u00e9g\u00e9n\u00e9ration 8s), coquelicot (vision nocturne 5s), orchid\u00e9e bleue (saturation), pissenlit (saturation), tulipe (faiblesse 9s), oxeye daisy (r\u00e9g\u00e9n\u00e9ration 8s). Cisailles : transforme en vache normale + 5 champignons rouges." }, { heading: "Variante brune et foudre", content: "La mooshroom rouge est la variante par d\u00e9faut. La mooshroom brune ne peut \u00eatre obtenue qu'en frappant une mooshroom rouge avec la foudre (via l'enchantement Canalisation sur un trident pendant un orage). La foudre transforme rouge en brune et vice versa. La mooshroom brune est fonctionnellement identique mais extr\u00eamement rare \u00e0 cause de la m\u00e9thode d'obtention." }, { heading: "Reproduction", content: "Nourrissez deux mooshrooms avec du bl\u00e9 pour les faire se reproduire (comme les vaches normales). Le b\u00e9b\u00e9 est toujours une mooshroom (rouge ou brune selon les parents). Les mooshrooms ne se reproduisent pas avec des vaches normales. Le b\u00e9b\u00e9 grandit en 20 minutes, acc\u00e9l\u00e9rable avec du bl\u00e9." }], tips: ["Les mooshrooms ont 10 PV (5 c\u0153urs) et spawnt uniquement dans le biome champignon", "Traite avec un bol = rago\u00fbt de champignon gratuit et infini", "Nourrissez-la avec une fleur puis traite-la pour une soupe suspecte aux effets sp\u00e9ciaux", "Les cisailles la transforment en vache normale + 5 champignons", "La foudre (Canalisation sur trident) transforme rouge en brune et inversement"], faq: [{ question: "Peut-on emmener une vache champignon hors du biome ?", answer: "Oui, une fois captur\u00e9e, la mooshroom survit dans tous les biomes ind\u00e9finiment. Utilisez une laisse (2 ficelles + 1 boule de slime) ou un bateau pour la transporter. Elle ne se transforme pas en vache normale spontan\u00e9ment, seules les cisailles provoquent cette transformation." }, { question: "La soupe suspecte donne-t-elle des effets diff\u00e9rents selon la fleur ?", answer: "Oui, chaque fleur donne un effet unique quand on nourrit la mooshroom avant de la traire. P\u00e2querette = R\u00e9g\u00e9n\u00e9ration (8s), coquelicot = Vision nocturne (5s), orchid\u00e9e bleue = Saturation, tulipe = Faiblesse (9s), muguet = Empoisonnement (12s), allium = R\u00e9sistance au feu (4s), bleuet = C\u00e9cit\u00e9 (8s)." }], relatedSlugs: ["axolotl-bleu", "apprivoiser-cheval", "poisson-globe", "metier-villageois", "reproduire-villageois"] } },
  { slug: "chauve-souris", keyword: "chauve souris minecraft", title: "Chauve-Souris Minecraft : Tout Savoir", h1: "La Chauve-Souris dans Minecraft", metaDescription: "Tout sur la chauve-souris Minecraft. Mob passif des grottes, spawning, comportement et inutilit\u00e9 assum\u00e9e de cette cr\u00e9ature.", category: "mobs", volume: 140, content: { intro: "La chauve-souris est le plus petit mob de Minecraft avec seulement 6 PV (3 c\u0153urs). C'est une cr\u00e9ature passive purement atmosph\u00e9rique qui vole dans les grottes sans aucun drop, aucune XP et aucune interaction utile. Malgr\u00e9 cela, elle contribue \u00e0 l'ambiance souterraine du jeu.", sections: [{ heading: "Caract\u00e9ristiques et statistiques", content: "La chauve-souris poss\u00e8de 6 PV (3 c\u0153urs) et mesure 0,9 bloc de haut par 0,5 bloc de large. Elle ne donne aucun drop \u00e0 sa mort, aucune XP et ne peut pas \u00eatre apprivois\u00e9e ou captur\u00e9e. C'est l'un des rares mobs qui n'a strictement aucune utilit\u00e9 dans le gameplay. Elle se pose au plafond quand elle est inactive et s'envole d\u00e8s qu'un joueur s'approche \u00e0 moins de 4 blocs." }, { heading: "Conditions de spawn", content: "Les chauves-souris spawnt dans les grottes et cavernes en dessous de Y=63 \u00e0 un niveau de lumi\u00e8re de 3 ou moins (\u00e9dition Java). Elles sont plus fr\u00e9quentes \u00e0 basse altitude. En octobre (pour Halloween), les conditions de spawn sont assouplies dans l'\u00e9dition Java : elles peuvent spawner \u00e0 un niveau de lumi\u00e8re de 6 ou moins, les rendant nettement plus communes pendant cette p\u00e9riode." }, { heading: "Comportement de vol", content: "Les chauves-souris volent de mani\u00e8re erratique dans les espaces souterrains. Quand elles sont inactives, elles se pendent au plafond la t\u00eate en bas et s'envolent si un joueur s'approche. Elles ne suivent aucun sch\u00e9ma de vol particulier et ne ciblent rien. Elles peuvent se noyer dans l'eau et br\u00fbler dans la lave comme n'importe quel mob." }], tips: ["La chauve-souris a 6 PV (3 c\u0153urs) et ne donne aucun drop ni XP", "Elle spawne dans les grottes sous Y=63 \u00e0 un niveau de lumi\u00e8re de 3 ou moins", "Plus fr\u00e9quente en octobre pour Halloween (\u00e9dition Java)", "C'est le plus petit mob du jeu et le seul mob volant passif de l'Overworld", "Purement atmosph\u00e9rique : aucune interaction, apprivoisement ou capture possible"], faq: [{ question: "La chauve-souris sert-elle \u00e0 quelque chose ?", answer: "Non, la chauve-souris est strictement atmosph\u00e9rique. Elle ne donne aucun drop, aucune XP, ne peut pas \u00eatre apprivois\u00e9e et n'a aucune interaction utile. Mojang l'a ajout\u00e9e en version 1.4.2 uniquement pour l'ambiance des grottes. C'est souvent consid\u00e9r\u00e9 comme le mob le plus inutile du jeu." }, { question: "Peut-on capturer une chauve-souris ?", answer: "Non, les chauves-souris ne peuvent pas \u00eatre captur\u00e9es avec un seau d'eau, une laisse ou tout autre moyen. Elles ne peuvent pas non plus \u00eatre apprivois\u00e9es. Vous pouvez uniquement les invoquer avec la commande /summon bat." }], relatedSlugs: ["poisson-globe", "vache-champignon", "axolotl-bleu", "apprivoiser-chat", "metier-villageois"] } },
  { slug: "bebe-villageois", keyword: "b\u00e9b\u00e9 villageois minecraft", title: "B\u00e9b\u00e9 Villageois Minecraft : Guide", h1: "Les B\u00e9b\u00e9s Villageois dans Minecraft", metaDescription: "Tout sur les b\u00e9b\u00e9s villageois Minecraft. Reproduction, croissance, comportement et comment les prot\u00e9ger dans votre village.", category: "mobs", volume: 170, content: { intro: "Les b\u00e9b\u00e9s villageois sont les versions enfants des villageois adultes dans Minecraft. Ils poss\u00e8dent 20 PV (10 c\u0153urs) comme les adultes, mais sont plus petits (0,975 bloc de haut, 0,3 bloc de large) et courent plus vite. Ils grandissent en exactement 20 minutes de jeu et n'ont ni m\u00e9tier ni capacit\u00e9 de commerce pendant leur enfance.", sections: [{ heading: "Comment obtenir des b\u00e9b\u00e9s villageois", content: "Les b\u00e9b\u00e9s naissent quand deux villageois adultes volontaires se reproduisent. Les conditions sont : un lit libre non-r\u00e9clam\u00e9 avec 2 blocs d'espace au-dessus, et assez de nourriture (3 pains, 12 carottes, 12 pommes de terre ou 12 betteraves) dans l'inventaire de chaque parent. Lancez de la nourriture aux villageois adultes pour remplir leur inventaire. Un villageois fermier partage automatiquement sa nourriture." }, { heading: "Comportement unique", content: "Les b\u00e9b\u00e9s villageois courent sensiblement plus vite que les adultes. Ils mesurent 0,975 bloc de haut et 0,3 bloc de large, ce qui leur permet de passer dans des espaces de 1 bloc de haut. Ils jouent entre eux en courant et sautant. La nuit, ils cherchent un lit libre pour dormir. Ils n'ont pas de m\u00e9tier et ne peuvent pas commercer. Les zombies les ciblent comme les villageois adultes." }, { heading: "Croissance et attribution de m\u00e9tier", content: "Les b\u00e9b\u00e9s grandissent en exactement 20 minutes de temps de jeu (pas de temps r\u00e9el). La croissance ne peut PAS \u00eatre acc\u00e9l\u00e9r\u00e9e avec de la nourriture (contrairement aux animaux). Une fois adultes, ils cherchent automatiquement un bloc de travail non-r\u00e9clam\u00e9 \u00e0 proximit\u00e9 pour adopter un m\u00e9tier. Vous pouvez influencer leur futur m\u00e9tier en pla\u00e7ant le bloc de t\u00e2che souhait\u00e9 \u00e0 proximit\u00e9 avant qu'ils ne deviennent adultes." }, { heading: "Protection contre les zombies", content: "Les zombies attaquent les villageois de jour comme de nuit. Un villageois tu\u00e9 par un zombie a une chance de devenir un zombie-villageois (50% en difficult\u00e9 Normale, 100% en Difficile). \u00c9clairez votre village avec des torches (niveau de lumi\u00e8re 8+), entourez-le de murs ou de cl\u00f4tures, et placez des golems de fer (100 PV, 7-21 d\u00e9g\u00e2ts en Normal) pour prot\u00e9ger tous les villageois, b\u00e9b\u00e9s compris." }], tips: ["Les b\u00e9b\u00e9s villageois ont 20 PV et grandissent en exactement 20 minutes de jeu", "Ils mesurent 0,975 bloc de haut et passent dans des espaces de 1 bloc", "La croissance ne peut PAS \u00eatre acc\u00e9l\u00e9r\u00e9e avec de la nourriture", "Prot\u00e9gez-les des zombies avec de l'\u00e9clairage, des murs et des golems de fer", "Placez le bloc de travail souhait\u00e9 \u00e0 proximit\u00e9 avant qu'ils ne grandissent"], faq: [{ question: "Les b\u00e9b\u00e9s villageois peuvent-ils mourir ?", answer: "Oui, ils ont 20 PV comme les adultes mais sont vuln\u00e9rables aux zombies, chutes, noyade et autres d\u00e9g\u00e2ts. En difficult\u00e9 Normale, un villageois tu\u00e9 par un zombie a 50% de chance de devenir zombie-villageois. En Difficile, c'est 100%. Prot\u00e9gez votre village avec de l'\u00e9clairage et des golems de fer." }, { question: "Un b\u00e9b\u00e9 villageois zombie peut-il \u00eatre gu\u00e9ri ?", answer: "Oui, la m\u00e9thode est la m\u00eame que pour un adulte : lancez une potion de faiblesse splash puis donnez-lui une pomme dor\u00e9e (clic droit). Le processus prend 3 \u00e0 5 minutes. Le b\u00e9b\u00e9 gu\u00e9ri restera un b\u00e9b\u00e9 et grandira normalement en 20 minutes. Il offrira aussi des r\u00e9ductions permanentes sur ses futurs \u00e9changes." }], relatedSlugs: ["reproduire-villageois", "metier-villageois", "echange-villageois", "trouver-village", "apprivoiser-cheval"] } },
  { slug: "poisson-globe", keyword: "poisson globe minecraft", title: "Poisson Globe Minecraft : Guide Complet", h1: "Le Poisson Globe dans Minecraft", metaDescription: "Le poisson-globe Minecraft est un ingr\u00e9dient de potion crucial. O\u00f9 le trouver, poison, et recette de respiration aquatique.", category: "mobs", volume: 320, content: { intro: "Le poisson-globe est un petit mob aquatique neutre poss\u00e9dant 3 PV (1,5 c\u0153ur) qui gonfle et empoisonne les joueurs \u00e0 proximit\u00e9. C'est une cr\u00e9ature neutre : elle n'attaque pas activement mais inflige des d\u00e9g\u00e2ts d\u00e9fensifs quand on s'approche trop. Malgr\u00e9 sa dangerosit\u00e9, il est indispensable comme ingr\u00e9dient de la potion de respiration aquatique.", sections: [{ heading: "O\u00f9 trouver le poisson-globe", content: "Les poissons-globes spawnt naturellement dans les oc\u00e9ans chauds et ti\u00e8des, en groupes de 1 \u00e0 3. Ils nagent \u00e0 faible profondeur. Ils peuvent aussi \u00eatre p\u00each\u00e9s dans n'importe quel plan d'eau avec une canne \u00e0 p\u00eache (cat\u00e9gorie \u00ab poisson \u00bb, environ 13% de chance par prise r\u00e9ussie). Capturez-les avec un seau d'eau (clic droit) pour les transporter sans subir leur poison." }, { heading: "M\u00e9canisme de gonflage et poison", content: "Le poisson-globe a 3 stades de gonflage selon la distance du joueur. \u00c0 plus de 2 blocs : petit et inoffensif. Entre 2 et 1 blocs : semi-gonfl\u00e9 (pas de d\u00e9g\u00e2ts). \u00c0 moins de 1 bloc : compl\u00e8tement gonfl\u00e9, inflige Poison II pendant 7 secondes (en difficult\u00e9 Normale) et des d\u00e9g\u00e2ts de contact de 2 (Facile), 3 (Normal) ou 4 (Difficile)." }, { heading: "Ingr\u00e9dient de potion essentiel", content: "Le poisson-globe est l'ingr\u00e9dient cl\u00e9 de la potion de respiration aquatique. Recette : brassez une verrue du Nether + fiole d'eau = potion maladroite, puis potion maladroite + poisson-globe = potion de respiration aquatique (3 min). Ajoutez de la poudre de redstone pour prolonger \u00e0 8 minutes. C'est indispensable pour explorer les monuments sous-marins et les ruines oc\u00e9aniques." }, { heading: "Ne mangez jamais de poisson-globe", content: "Manger un poisson-globe cru est extr\u00eamement dangereux : il inflige Faim III pendant 15 secondes, Poison II pendant 1 minute et Naus\u00e9e pendant 15 secondes. Il ne restaure que 1 point de faim et 0,2 de saturation. C'est l'un des pires aliments du jeu. Gardez-le exclusivement pour les potions." }], tips: ["Le poisson-globe a 3 PV et inflige Poison II (7s) + 3 d\u00e9g\u00e2ts de contact en Normal", "Capturez-le avec un seau d'eau pour \u00e9viter le poison", "Ingr\u00e9dient essentiel de la potion de respiration aquatique (3 min, 8 min avec redstone)", "Se trouve dans les oc\u00e9ans chauds/ti\u00e8des et par la p\u00eache", "Ne le mangez JAMAIS : il inflige Faim III, Poison II et Naus\u00e9e simultan\u00e9ment"], faq: [{ question: "Peut-on manger le poisson-globe ?", answer: "Techniquement oui, mais c'est extr\u00eamement dangereux. Il inflige Faim III (15s), Poison II (1 min) et Naus\u00e9e (15s) pour seulement 1 point de faim et 0,2 de saturation. C'est l'un des pires aliments du jeu. R\u00e9servez-le exclusivement pour la fabrication de potions de respiration aquatique." }, { question: "Comment p\u00eacher un poisson-globe ?", answer: "Lancez votre ligne dans n'importe quel plan d'eau. Le poisson-globe fait partie de la cat\u00e9gorie \u00ab poisson \u00bb avec environ 13% de chance par prise r\u00e9ussie. L'enchantement Chance de la Mer n'augmente pas les chances de poisson mais les tr\u00e9sors. L'enchantement App\u00e2t (Lure) est plus utile car il r\u00e9duit le temps d'attente entre les prises." }], relatedSlugs: ["poisson-argent", "axolotl-bleu", "vache-champignon", "chauve-souris", "metier-villageois"] } },
  { slug: "poisson-argent", keyword: "poisson d argent minecraft", title: "Poisson d'Argent Minecraft : Guide", h1: "Le Poisson d'Argent (Silverfish) dans Minecraft", metaDescription: "Le poisson d'argent Minecraft se cache dans la pierre des forteresses. Comment les identifier, les combattre et \u00e9viter les essaims.", category: "mobs", volume: 210, content: { intro: "Le poisson d'argent (silverfish) est un petit mob hostile poss\u00e9dant 8 PV (4 c\u0153urs) qui se cache dans les blocs de pierre infest\u00e9e. On le trouve principalement dans les forteresses de l'End et dans les biomes de montagne. Quand un bloc infest\u00e9 est cass\u00e9 ou qu'un silverfish est attaqu\u00e9, il appelle ses cong\u00e9n\u00e8res cach\u00e9s \u00e0 proximit\u00e9, pouvant d\u00e9clencher un essaim dangereux.", sections: [{ heading: "Blocs infest\u00e9s et localisation", content: "Les silverfish se cachent dans des blocs de pierre infest\u00e9e qui ressemblent parfaitement \u00e0 de la pierre normale, pierre taill\u00e9e, pav\u00e9, pierre taill\u00e9e moussue, pierre taill\u00e9e craquel\u00e9e ou pierre taill\u00e9e sculpt\u00e9e. La diff\u00e9rence subtile : les blocs infest\u00e9s se cassent l\u00e9g\u00e8rement plus vite que la normale et ne donnent aucun drop. Dans les forteresses, la salle du portail de l'End est enti\u00e8rement construite en pierre taill\u00e9e infest\u00e9e. Les biomes de montagne g\u00e9n\u00e8rent aussi de la pierre infest\u00e9e." }, { heading: "M\u00e9canisme d'essaim", content: "Quand un silverfish est attaqu\u00e9 (mais pas tu\u00e9 en un coup), il \u00e9met un signal qui r\u00e9veille tous les silverfish cach\u00e9s dans les blocs infest\u00e9s dans un rayon de 21 blocs horizontalement et 11 blocs verticalement. Un seul silverfish bless\u00e9 peut d\u00e9clencher un essaim de dizaines de mobs en quelques secondes. C'est le principal danger de cette cr\u00e9ature : individuellement faible (8 PV, 1 d\u00e9g\u00e2t) mais extr\u00eamement dangereux en groupe." }, { heading: "Strat\u00e9gies de combat", content: "La r\u00e8gle d'or : tuez chaque silverfish en UN SEUL coup pour emp\u00eacher l'appel aux renforts. Une \u00e9p\u00e9e en fer avec Tranchant III ou une \u00e9p\u00e9e en diamant sans enchantement suffit. \u00c9vitez les \u00e9p\u00e9es avec Recul qui les repoussent sans les tuer. La lave et le feu les \u00e9liminent efficacement. L'enchantement Fl\u00e9au des arthropodes est tr\u00e8s efficace car les silverfish sont des arthropodes." }, { heading: "Pr\u00e9vention avec Toucher de Soie", content: "L'enchantement Toucher de Soie sur une pioche permet de miner les blocs infest\u00e9s sans lib\u00e9rer le silverfish \u00e0 l'int\u00e9rieur. Le bloc est r\u00e9cup\u00e9r\u00e9 normalement. C'est la m\u00e9thode la plus s\u00fbre pour traverser les forteresses sans d\u00e9clencher d'essaim. En mode F3 (\u00e9dition Java), les blocs infest\u00e9s sont identifi\u00e9s comme \u00ab infested_stone \u00bb au lieu de \u00ab stone \u00bb." }], tips: ["Les silverfish ont 8 PV (4 c\u0153urs) et infligent 1 d\u00e9g\u00e2t en difficult\u00e9 Normale", "Les blocs infest\u00e9s se cassent plus vite et ne donnent aucun drop", "Tuez-les en un seul coup pour \u00e9viter l'appel aux renforts (essaim)", "Toucher de Soie emp\u00eache le silverfish de sortir du bloc min\u00e9", "Fl\u00e9au des arthropodes est tr\u00e8s efficace car ce sont des arthropodes"], faq: [{ question: "Comment reconna\u00eetre un bloc infest\u00e9 ?", answer: "Un bloc infest\u00e9 se casse l\u00e9g\u00e8rement plus vite que la pierre normale et ne donne aucun drop quand min\u00e9 sans Toucher de Soie. En \u00e9dition Java avec F3, passez la souris sur le bloc : \u00ab infested_stone \u00bb au lieu de \u00ab stone \u00bb. En cas de doute dans une forteresse, minez tout avec Toucher de Soie." }, { question: "Les silverfish sont-ils dangereux ?", answer: "Individuellement non : 8 PV et seulement 1 d\u00e9g\u00e2t en Normal. Mais en essaim, ils sont tr\u00e8s dangereux. Un seul silverfish bless\u00e9 (pas tu\u00e9) peut alerter des dizaines de cong\u00e9n\u00e8res cach\u00e9s dans les blocs environnants. L'accumulation de d\u00e9g\u00e2ts d'un essaim est mortelle. Tuez-les toujours en un coup." }], relatedSlugs: ["poisson-globe", "metier-villageois", "chauve-souris", "vache-champignon", "trouver-village"] } },
  { slug: "trouver-village", keyword: "comment trouver un village dans minecraft", title: "Trouver un Village Minecraft : Guide", h1: "Comment Trouver un Village dans Minecraft", metaDescription: "Trouvez un village Minecraft rapidement. Biomes de g\u00e9n\u00e9ration, commande /locate et strat\u00e9gies d'exploration efficaces.", category: "mobs", volume: 390, content: { intro: "Les villages sont des structures essentielles dans Minecraft pour le commerce avec les villageois (20 PV, passifs), l'acc\u00e8s aux cultures gratuites et les ressources des coffres. Ils se g\u00e9n\u00e8rent dans 7 biomes diff\u00e9rents (plaines, d\u00e9sert, savane, ta\u00efga, neige, jungle et marais) avec une architecture adapt\u00e9e \u00e0 chaque biome.", sections: [{ heading: "Biomes de g\u00e9n\u00e9ration des villages", content: "Les villages se g\u00e9n\u00e8rent dans 7 biomes : plaines (le plus commun), d\u00e9sert (gr\u00e8s), savane (acacia), ta\u00efga (sapin), toundra enneig\u00e9e (bois de sapin et neige), jungle et marais. Les villages de plaines sont les plus fr\u00e9quents car les plaines sont un biome courant. Les villages de jungle et de marais sont les plus rares. Chaque biome donne un style architectural unique et des cultures diff\u00e9rentes." }, { heading: "Commande /locate", content: "En mode cr\u00e9atif ou avec les cheats activ\u00e9s, tapez /locate structure minecraft:village pour obtenir les coordonn\u00e9es du village le plus proche. La commande affiche les coordonn\u00e9es X, Y, Z exactes. Tapez ensuite /tp @s X Y Z pour vous y t\u00e9l\u00e9porter. En \u00e9dition Bedrock, la commande est /locate structure village. C'est la m\u00e9thode la plus rapide et la plus pr\u00e9cise." }, { heading: "Exploration efficace en Survie", content: "Sans commandes, montez sur les collines et points hauts pour rep\u00e9rer les villages \u00e0 distance gr\u00e2ce \u00e0 leurs structures visibles (chemins, maisons, clochers). Suivez les chemins de terre naturels qui connectent parfois les villages entre eux. Utilisez un bateau sur les rivi\u00e8res pour explorer rapidement les plaines adjacentes. Explorez en spirale autour de votre spawn pour couvrir un maximum de terrain." }, { heading: "Structures et contenu d'un village", content: "Un village typique contient : des maisons de villageois, une place centrale avec un puits, des cultures (bl\u00e9, carottes, pommes de terre, betteraves), des blocs de travail d\u00e9finissant les m\u00e9tiers des villageois, un clocher et parfois une forge avec un coffre contenant du fer, de l'or et d'autres ressources. Le nombre de villageois d\u00e9pend de la taille du village (g\u00e9n\u00e9ralement 5 \u00e0 10)." }], tips: ["Les villages de plaines sont les plus courants et les plus faciles \u00e0 trouver", "7 biomes g\u00e9n\u00e8rent des villages : plaines, d\u00e9sert, savane, ta\u00efga, neige, jungle, marais", "Montez sur les collines pour rep\u00e9rer les villages \u00e0 distance", "Les chemins de terre naturels peuvent mener \u00e0 un village", "/locate structure minecraft:village donne les coordonn\u00e9es exactes"], faq: [{ question: "\u00c0 quelle distance le village le plus proche se trouve-t-il ?", answer: "Les villages se g\u00e9n\u00e8rent en moyenne tous les 32 chunks (512 blocs) avec un espacement minimum de 8 chunks (128 blocs) dans les biomes appropri\u00e9s. Depuis le spawn, le village le plus proche est g\u00e9n\u00e9ralement \u00e0 500-1500 blocs, mais cela d\u00e9pend des biomes g\u00e9n\u00e9r\u00e9s autour du point de spawn." }, { question: "Tous les villages ont-ils les m\u00eames structures ?", answer: "Non, le style architectural d\u00e9pend du biome : plaines (ch\u00eane), d\u00e9sert (gr\u00e8s), savane (acacia), ta\u00efga (sapin), neige (sapin + neige), jungle (jungle + bambou), marais (ch\u00eane des marais). Les structures internes (forge, biblioth\u00e8que, temple) varient aussi al\u00e9atoirement d'un village \u00e0 l'autre." }], relatedSlugs: ["metier-villageois", "reproduire-villageois", "echange-villageois", "bebe-villageois", "apprivoiser-cheval"] } },
  { slug: "reproduire-chevaux", keyword: "reproduire chevaux minecraft", title: "Reproduire des Chevaux Minecraft : Guide", h1: "Comment Reproduire des Chevaux dans Minecraft", metaDescription: "Reproduisez des chevaux Minecraft avec des pommes dor\u00e9es. \u00c9levage s\u00e9lectif, statistiques et obtention du cheval parfait.", category: "mobs", volume: 170, content: { intro: "La reproduction de chevaux dans Minecraft permet d'obtenir des montures aux statistiques am\u00e9lior\u00e9es. Chaque cheval poss\u00e8de 3 statistiques ind\u00e9pendantes : sant\u00e9 (15-30 PV), vitesse (4,74-14,23 blocs/s) et hauteur de saut (1,09-5,29 blocs). En \u00e9levant s\u00e9lectivement les meilleurs chevaux, vous pouvez cr\u00e9er des montures significativement sup\u00e9rieures aux chevaux sauvages.", sections: [{ heading: "Nourriture de reproduction", content: "Les chevaux se reproduisent avec deux aliments : pommes dor\u00e9es (1 pomme + 8 lingots d'or sur la table de craft) ou carottes dor\u00e9es (1 carotte + 8 p\u00e9pites d'or). Les carottes dor\u00e9es co\u00fbtent environ 1 lingot d'or (8 p\u00e9pites = 1 lingot) contre 8 lingots pour la pomme dor\u00e9e, ce qui les rend 8 fois moins ch\u00e8res. Les deux parents doivent \u00eatre apprivois\u00e9s avant de pouvoir se reproduire. Le d\u00e9lai entre deux reproductions est de 5 minutes." }, { heading: "H\u00e9ritage des statistiques", content: "Les statistiques du poulain sont calcul\u00e9es ainsi : (stat parent 1 + stat parent 2 + valeur al\u00e9atoire) / 3. La valeur al\u00e9atoire est tir\u00e9e d'une distribution qui tend vers la moyenne. En cons\u00e9quence, les poulains de parents avec de bonnes stats ont PLUS de chances d'avoir de bonnes stats, mais le r\u00e9sultat n'est jamais garanti. \u00c9levez plusieurs g\u00e9n\u00e9rations pour une am\u00e9lioration progressive." }, { heading: "\u00c9levage s\u00e9lectif", content: "Construisez une piste de 100 blocs chronom\u00e9tr\u00e9e pour tester la vitesse. Gardez uniquement les chevaux les plus rapides (moins de 7-8 secondes pour 100 blocs = excellent). Testez le saut avec des obstacles de hauteur croissante. Reproduisez les meilleurs chevaux entre eux pendant plusieurs g\u00e9n\u00e9rations. Apr\u00e8s 3-4 g\u00e9n\u00e9rations d'\u00e9levage s\u00e9lectif, vous obtiendrez des chevaux nettement sup\u00e9rieurs aux sauvages." }, { heading: "Croisements sp\u00e9ciaux : mules", content: "Croisez un cheval avec un \u00e2ne en utilisant une pomme dor\u00e9e ou une carotte dor\u00e9e pour obtenir une mule. Les mules ne peuvent PAS se reproduire (elles sont st\u00e9riles) mais peuvent porter un coffre (clic droit avec un coffre) ajoutant 15 emplacements d'inventaire. Elles sont id\u00e9ales pour les exp\u00e9ditions longues n\u00e9cessitant du transport d'objets." }], tips: ["Les carottes dor\u00e9es co\u00fbtent ~1 lingot d'or vs 8 pour les pommes dor\u00e9es", "Les stats du poulain = (parent 1 + parent 2 + al\u00e9atoire) / 3", "Testez la vitesse sur une piste de 100 blocs chronom\u00e9tr\u00e9e", "\u00c2nes + chevaux = mules (st\u00e9riles mais portent un coffre de 15 emplacements)", "Plusieurs g\u00e9n\u00e9rations d'\u00e9levage s\u00e9lectif am\u00e9liorent significativement les stats"], faq: [{ question: "Les mules peuvent-elles se reproduire ?", answer: "Non, les mules (croisement \u00e2ne + cheval) sont st\u00e9riles et ne peuvent pas se reproduire entre elles ni avec d'autres \u00e9quid\u00e9s. Pour obtenir une nouvelle mule, vous devez toujours croiser un cheval apprivois\u00e9 avec un \u00e2ne apprivois\u00e9 en utilisant une pomme dor\u00e9e ou une carotte dor\u00e9e." }, { question: "Combien de temps met un poulain \u00e0 grandir ?", answer: "Un poulain met 20 minutes de temps de jeu \u00e0 devenir adulte. Vous pouvez acc\u00e9l\u00e9rer sa croissance en le nourrissant : sucre (-30s), bl\u00e9 (-20s), pomme (-1min), pomme dor\u00e9e (-4min), carotte dor\u00e9e (-1min), botte de foin (-3min). Une botte de foin est le meilleur rapport acc\u00e9l\u00e9rateur, r\u00e9duisant le temps de croissance de 3 minutes par botte." }], relatedSlugs: ["apprivoiser-cheval", "cheval-squelette", "reproduire-villageois", "metier-villageois", "apprivoiser-renard"] } },
  { slug: "echange-villageois", keyword: "\u00e9change villageois minecraft", title: "\u00c9changes Villageois Minecraft : Guide Complet", h1: "Tous les \u00c9changes des Villageois dans Minecraft", metaDescription: "Guide complet des \u00e9changes avec les villageois Minecraft. Meilleurs trades, niveaux et comment obtenir les meilleures offres.", category: "mobs", volume: 260, content: { intro: "Le syst\u00e8me d'\u00e9change des villageois est l'une des m\u00e9caniques les plus riches de Minecraft. Chaque villageois (20 PV, passif) poss\u00e8de un m\u00e9tier avec des \u00e9changes uniques r\u00e9partis sur 5 niveaux de progression (Novice, Apprenti, Compagnon, Expert, Ma\u00eetre). Les \u00e9changes utilisent des \u00e9meraudes comme monnaie. Ma\u00eetriser ce syst\u00e8me donne acc\u00e8s \u00e0 des enchantements rares, des outils en diamant et des ressources pr\u00e9cieuses.", sections: [{ heading: "Comment \u00e9changer avec un villageois", content: "Faites un clic droit sur un villageois avec un m\u00e9tier pour ouvrir son interface d'\u00e9change. Les offres sont r\u00e9parties en onglets correspondant aux niveaux. Chaque \u00e9change a un nombre d'utilisations limit\u00e9 (g\u00e9n\u00e9ralement 12-16 par offre) qui se renouvelle 2 fois par jour quand le villageois acc\u00e8de \u00e0 son bloc de t\u00e2che. Commercer donne de l'XP au villageois (le faisant progresser) et au joueur (3-6 XP par \u00e9change, 8-11 si le villageois est \u00ab pr\u00eat \u00bb)." }, { heading: "Meilleurs \u00e9changes par m\u00e9tier", content: "Biblioth\u00e9caire (pupitre) : vend des livres enchant\u00e9s \u00e0 tous les niveaux, dont Raccommodage au niveau Novice (r\u00e9initialisable). Fermier (composteur) : ach\u00e8te 20 bl\u00e9 pour 1 \u00e9meraude, excellent revenu. Ma\u00e7on (tailleur de pierre) : ach\u00e8te 20 pierres pour 1 \u00e9meraude. Boucher (fumoir) : ach\u00e8te 14 poulets crus pour 1 \u00e9meraude. Armurier (haut fourneau) : vend armure en diamant enchant\u00e9e au niveau Ma\u00eetre. Forgeron d'outils (table de forgeron) : vend pioche/hache en diamant enchant\u00e9e. Fl\u00e9chier (table d'archerie) : vend des fl\u00e8ches \u00e0 pointe au niveau Expert/Ma\u00eetre." }, { heading: "R\u00e9ductions de prix", content: "Gu\u00e9rir un villageois zombie offre des r\u00e9ductions permanentes massives sur TOUS ses \u00e9changes. M\u00e9thode : lancez une potion de faiblesse splash sur un villageois zombie, puis donnez-lui une pomme dor\u00e9e (clic droit). Apr\u00e8s 3-5 minutes de gu\u00e9rison, le villageois offrira des prix r\u00e9duits de fa\u00e7on permanente. R\u00e9p\u00e9tez jusqu'\u00e0 5 fois pour des prix quasi gratuits (1 \u00e9meraude pour presque tout). L'effet H\u00e9ros du Village (apr\u00e8s un raid) donne aussi des r\u00e9ductions temporaires." }, { heading: "Offre et demande", content: "Le syst\u00e8me d'offre et demande influence les prix : un \u00e9change utilis\u00e9 trop souvent augmente son prix, et un \u00e9change peu utilis\u00e9 reste au prix de base. Les villageois r\u00e9cemment gu\u00e9ris d'un zombie offrent les meilleures r\u00e9ductions. Diversifiez vos \u00e9changes pour maintenir des prix bas. Le renouvellement des prix se fait quand le villageois travaille \u00e0 son bloc de t\u00e2che (2 fois par jour)." }], tips: ["Les villageois ont 5 niveaux : Novice, Apprenti, Compagnon, Expert, Ma\u00eetre", "Gu\u00e9rissez les villageois zombies pour des r\u00e9ductions permanentes \u00e9normes (jusqu'\u00e0 1 \u00e9meraude)", "Le biblioth\u00e9caire est le meilleur pour Raccommodage et les enchantements rares", "Vendez du bl\u00e9 au fermier ou de la pierre au ma\u00e7on pour des \u00e9meraudes faciles", "Les \u00e9changes se renouvellent 2 fois par jour quand le villageois acc\u00e8de \u00e0 son bloc de t\u00e2che"], faq: [{ question: "Comment avoir des r\u00e9ductions permanentes ?", answer: "Gu\u00e9rissez un villageois zombie (potion de faiblesse splash + pomme dor\u00e9e). Le processus prend 3-5 minutes. Le villageois gu\u00e9ri offre des r\u00e9ductions permanentes sur tous ses \u00e9changes. Vous pouvez r\u00e9p\u00e9ter le cycle de zombification/gu\u00e9rison (avec un zombie) jusqu'\u00e0 5 fois pour atteindre le prix minimum d'1 \u00e9meraude pour la plupart des \u00e9changes." }, { question: "Les villageois peuvent-ils proposer Raccommodage ?", answer: "Oui, les biblioth\u00e9caires (avec pupitre) peuvent proposer Raccommodage comme livre enchant\u00e9 d\u00e8s le niveau Novice. Si un biblioth\u00e9caire novice ne le propose pas, cassez le pupitre, attendez qu'il perde son m\u00e9tier, replacez le pupitre et v\u00e9rifiez les nouvelles offres. R\u00e9p\u00e9tez jusqu'\u00e0 obtenir Raccommodage. Ne faites AUCUN \u00e9change avant d'avoir l'offre souhait\u00e9e." }], relatedSlugs: ["metier-villageois", "reproduire-villageois", "trouver-village", "bebe-villageois", "enlever-metier-villageois"] } },
  { slug: "carotte-doree", keyword: "carotte dor\u00e9e minecraft", title: "Carotte Dor\u00e9e Minecraft : Craft et Utilisations", h1: "La Carotte Dor\u00e9e dans Minecraft", metaDescription: "Craftez la carotte dor\u00e9e Minecraft pour les potions de vision nocturne et la reproduction de chevaux. Recette et utilisations.", category: "mobs", volume: 210, content: { intro: "La carotte dor\u00e9e est un item polyvalent dans Minecraft : c'est le meilleur aliment du jeu en saturation (14,4), l'ingr\u00e9dient cl\u00e9 de la potion de vision nocturne, et l'aliment de reproduction des chevaux et des lapins. Son co\u00fbt mod\u00e9r\u00e9 (1 carotte + 8 p\u00e9pites d'or, soit environ 1 lingot d'or) en fait un item extr\u00eamement rentable.", sections: [{ heading: "Recette de craft", content: "Placez 1 carotte au centre de la grille de craft et entourez-la de 8 p\u00e9pites d'or. Les p\u00e9pites d'or s'obtiennent en pla\u00e7ant 1 lingot d'or dans la grille (1 lingot = 9 p\u00e9pites). Le co\u00fbt r\u00e9el est donc l\u00e9g\u00e8rement inf\u00e9rieur \u00e0 1 lingot d'or par carotte dor\u00e9e. Les villageois fermiers de niveau Ma\u00eetre en vendent aussi pour 3 \u00e9meraudes." }, { heading: "Meilleure saturation du jeu", content: "La carotte dor\u00e9e restaure 6 points de faim (3 cuisses) et 14,4 de saturation, la plus haute de tous les aliments du jeu. En comparaison : steak = 8 faim + 12,8 saturation, c\u00f4te de porc cuite = 8 faim + 12,8 saturation. La saturation d\u00e9termine combien de temps vous restez sans avoir faim apr\u00e8s avoir mang\u00e9. Pour les longues explorations, la carotte dor\u00e9e est l'aliment optimal." }, { heading: "Ingr\u00e9dient de potion", content: "Dans l'alambic, potion maladroite + carotte dor\u00e9e = potion de vision nocturne (3 min). Ajoutez de la poudre de redstone pour prolonger \u00e0 8 minutes. Ajoutez un \u0153il d'araign\u00e9e ferment\u00e9 pour transformer la vision nocturne en potion d'invisibilit\u00e9 (3 min). La vision nocturne est essentielle pour l'exploration sous-marine et souterraine." }, { heading: "Reproduction d'animaux", content: "La carotte dor\u00e9e est utilis\u00e9e pour reproduire les chevaux et les \u00e2nes (avec les pommes dor\u00e9es). Elle est 8 fois moins ch\u00e8re que la pomme dor\u00e9e (1 lingot d'or vs 8 lingots), ce qui en fait l'option pr\u00e9f\u00e9r\u00e9e pour l'\u00e9levage \u00e9quin. Elle sert aussi \u00e0 reproduire les lapins, bien que les pissenlits ou carottes fonctionnent aussi pour les lapins." }], tips: ["Meilleure saturation du jeu (14,4) devant le steak (12,8)", "Co\u00fbt : 1 carotte + 8 p\u00e9pites d'or (= environ 1 lingot d'or)", "Ingr\u00e9dient cl\u00e9 de la potion de vision nocturne (3 min / 8 min avec redstone)", "8 fois moins ch\u00e8re que la pomme dor\u00e9e pour la reproduction des chevaux", "Les fermiers de niveau Ma\u00eetre en vendent pour 3 \u00e9meraudes"], faq: [{ question: "La carotte dor\u00e9e est-elle meilleure que le steak ?", answer: "En saturation, oui : 14,4 contre 12,8 pour le steak. En points de faim, le steak est sup\u00e9rieur : 8 contre 6. La carotte dor\u00e9e vous garde rassasi\u00e9 plus longtemps mais restaure moins de barre de faim visible. Pour l'exploration longue dur\u00e9e, la carotte dor\u00e9e est optimale. Pour la restauration imm\u00e9diate de faim, le steak est meilleur." }, { question: "O\u00f9 trouver des carottes dor\u00e9es sans les crafter ?", answer: "Les carottes dor\u00e9es se trouvent dans les coffres des bastions du Nether (chance d'environ 8,3%) et des mines abandonn\u00e9es. Les fermiers villageois de niveau Ma\u00eetre en vendent pour 3 \u00e9meraudes. C'est l'un des rares items \u00e0 la fois craftables et trouvables dans les coffres." }], relatedSlugs: ["pomme-doree", "reproduire-chevaux", "apprivoiser-cheval", "oeil-araignee-fermente", "metier-villageois"] } },
  { slug: "pomme-doree", keyword: "pomme dor\u00e9e minecraft", title: "Pomme Dor\u00e9e Minecraft : Craft et Guide", h1: "La Pomme Dor\u00e9e dans Minecraft", metaDescription: "Craftez la pomme dor\u00e9e Minecraft pour soigner les villageois zombies. Recette, effets et diff\u00e9rence avec la pomme dor\u00e9e enchant\u00e9e.", category: "mobs", volume: 210, content: { intro: "La pomme dor\u00e9e est un item puissant dans Minecraft qui donne Absorption I (2 c\u0153urs suppl\u00e9mentaires pendant 2 minutes) et R\u00e9g\u00e9n\u00e9ration II (pendant 5 secondes). Elle est surtout connue pour son r\u00f4le crucial dans la gu\u00e9rison des villageois zombies (combin\u00e9e avec une potion de faiblesse), une technique essentielle pour obtenir des r\u00e9ductions permanentes chez les villageois.", sections: [{ heading: "Craft et variantes", content: "Pomme dor\u00e9e : placez 1 pomme au centre + 8 lingots d'or autour sur la table de craft. Effets : Absorption I (2 min) + R\u00e9g\u00e9n\u00e9ration II (5s). Co\u00fbt : 8 lingots d'or. La pomme dor\u00e9e enchant\u00e9e (Notch Apple) ne se craft PLUS depuis la version 1.9. Elle se trouve uniquement dans les coffres de donjons (1,4%), bastions du Nether (6,5%), temples du d\u00e9sert (2,6%) et mines abandonn\u00e9es (1,4%). Effets de la Notch Apple : Absorption IV (8 c\u0153urs, 2 min) + R\u00e9g\u00e9n\u00e9ration II (20s) + R\u00e9sistance au Feu (5 min) + R\u00e9sistance I (5 min)." }, { heading: "Gu\u00e9rir un villageois zombie", content: "Pour gu\u00e9rir un villageois zombie : 1) Lancez une potion de faiblesse splash sur le villageois zombie (ou utilisez une fl\u00e8che de faiblesse). 2) Donnez-lui une pomme dor\u00e9e (clic droit). 3) Le villageois tremble et \u00e9met des particules rouges pendant 3-5 minutes. 4) Une fois gu\u00e9ri, il offre des r\u00e9ductions permanentes sur tous ses futurs \u00e9changes. Astuce : pi\u00e9ger un villageois zombie pr\u00e8s d'un lit et de barres de fer acc\u00e9l\u00e8re la gu\u00e9rison." }, { heading: "Utilisation en PvP et combat", content: "En PvP, la pomme dor\u00e9e est un consommable de survie essentiel. L'Absorption I ajoute 2 c\u0153urs dor\u00e9s temporaires et la R\u00e9g\u00e9n\u00e9ration II restaure rapidement vos PV. Mangez-la juste avant un combat pour un avantage significatif. La pomme dor\u00e9e enchant\u00e9e est consid\u00e9r\u00e9e comme le meilleur consommable du jeu avec Absorption IV (8 c\u0153urs suppl\u00e9mentaires) + R\u00e9sistance I + R\u00e9sistance au Feu + R\u00e9g\u00e9n\u00e9ration II prolong\u00e9e." }, { heading: "Autres utilisations", content: "La pomme dor\u00e9e sert aussi \u00e0 : reproduire les chevaux (alternative \u00e0 la carotte dor\u00e9e, mais 8 fois plus ch\u00e8re), attirer et reproduire les \u00e2nes, crafter des banni\u00e8res avec motif pomme dor\u00e9e. En mode Hardcore, garder une pomme dor\u00e9e enchant\u00e9e est un filet de s\u00e9curit\u00e9 pr\u00e9cieux pour les situations critiques." }], tips: ["Craft : 1 pomme + 8 lingots d'or = pomme dor\u00e9e (Absorption I + R\u00e9g\u00e9n\u00e9ration II)", "Pomme dor\u00e9e + potion de faiblesse = gu\u00e9rison des villageois zombies (r\u00e9ductions permanentes)", "La pomme dor\u00e9e enchant\u00e9e ne se craft plus depuis la v1.9 (coffres uniquement)", "En PvP, mangez-la avant un combat pour l'Absorption I (2 c\u0153urs suppl\u00e9mentaires)", "8 lingots d'or par pomme dor\u00e9e : co\u00fbt mod\u00e9r\u00e9 en milieu de partie"], faq: [{ question: "O\u00f9 trouver une pomme dor\u00e9e enchant\u00e9e ?", answer: "Les pommes dor\u00e9es enchant\u00e9es se trouvent dans les coffres des donjons (1,4% de chance), bastions du Nether (6,5%), temples du d\u00e9sert (2,6%), mines abandonn\u00e9es (1,4%) et anciennes cit\u00e9s. Le bastion du Nether offre les meilleures chances. C'est l'un des items les plus rares et puissants du jeu." }, { question: "Peut-on encore crafter la pomme dor\u00e9e enchant\u00e9e ?", answer: "Non, depuis la version 1.9 (Combat Update, 2016), la pomme dor\u00e9e enchant\u00e9e ne peut plus \u00eatre craft\u00e9e. Avant, elle n\u00e9cessitait 1 pomme + 8 blocs d'or (72 lingots). D\u00e9sormais, elle est exclusivement disponible dans les coffres de certaines structures, ce qui en fait un tr\u00e9sor rare et pr\u00e9cieux." }], relatedSlugs: ["carotte-doree", "oeil-araignee-fermente", "reproduire-villageois", "metier-villageois", "echange-villageois"] } },
  { slug: "oeil-araignee-fermente", keyword: "oeil d'araign\u00e9e ferment\u00e9 minecraft", title: "Oeil d'Araign\u00e9e Ferment\u00e9 Minecraft : Guide", h1: "L'Oeil d'Araign\u00e9e Ferment\u00e9 dans Minecraft", metaDescription: "Craftez l'oeil d'araign\u00e9e ferment\u00e9 Minecraft pour les potions de faiblesse et d'invisibilit\u00e9. Recette et utilisations en alchimie.", category: "mobs", volume: 1000, content: { intro: "L'\u0153il d'araign\u00e9e ferment\u00e9 est un ingr\u00e9dient d'alchimie fondamental dans Minecraft. Il sert \u00e0 cr\u00e9er des potions n\u00e9gatives et \u00e0 corrompre des potions positives en leur oppos\u00e9. C'est la base de la potion de faiblesse (essentielle pour gu\u00e9rir les villageois zombies) et de l'invisibilit\u00e9. Un item indispensable pour tout alchimiste.", sections: [{ heading: "Recette de craft", content: "Combinez sur la table de craft (forme libre) : 1 \u0153il d'araign\u00e9e + 1 sucre + 1 champignon brun. L'\u0153il d'araign\u00e9e s'obtient en tuant des araign\u00e9es (0-1 drop, augment\u00e9 avec Butin). Les araign\u00e9es (16 PV, neutre le jour / hostile la nuit) spawnt la nuit en surface et dans les grottes. Le sucre se craft avec 1 canne \u00e0 sucre. Le champignon brun pousse dans les zones sombres (grottes, sous les arbres), dans le Nether et dans les biomes de marais et champignon." }, { heading: "Corruption de potions", content: "L'\u0153il d'araign\u00e9e ferment\u00e9 est un agent de corruption unique en alchimie. Il transforme les potions positives en n\u00e9gatives : Vision nocturne + OAF = Invisibilit\u00e9. Soin + OAF = D\u00e9g\u00e2ts instantan\u00e9s. Rapidit\u00e9 + OAF = Lenteur. Poison + OAF = D\u00e9g\u00e2ts instantan\u00e9s. Saut + OAF = Lenteur. C'est le seul ingr\u00e9dient qui inverse les effets des potions, rendant l'alchimie n\u00e9gative possible." }, { heading: "Potion de faiblesse directe", content: "La potion de faiblesse est unique : elle se brasse directement avec une fiole d'eau + \u0153il d'araign\u00e9e ferment\u00e9, SANS verrue du Nether ni potion maladroite interm\u00e9diaire. C'est la seule potion qui contourne compl\u00e8tement l'\u00e9tape de la potion maladroite. La faiblesse est cruciale pour gu\u00e9rir les villageois zombies (faiblesse splash + pomme dor\u00e9e). En version splash, elle r\u00e9duit aussi les d\u00e9g\u00e2ts de m\u00eal\u00e9e de 4 points." }, { heading: "Ingr\u00e9dient pour l'invisibilit\u00e9", content: "Pour obtenir la potion d'invisibilit\u00e9 : brassez d'abord une potion de vision nocturne (potion maladroite + carotte dor\u00e9e), puis ajoutez un \u0153il d'araign\u00e9e ferment\u00e9. L'invisibilit\u00e9 dure 3 minutes (8 minutes avec redstone). En version splash ou fl\u00e8che, c'est un outil strat\u00e9gique puissant en PvP et pour \u00e9viter les mobs." }], tips: ["Craft : 1 \u0153il d'araign\u00e9e + 1 sucre + 1 champignon brun (forme libre)", "L'OAF corrompt les potions positives en n\u00e9gatives (vision nocturne \u2192 invisibilit\u00e9)", "La potion de faiblesse ne n\u00e9cessite PAS de verrue du Nether (fiole d'eau + OAF)", "Indispensable pour gu\u00e9rir les villageois zombies (faiblesse splash + pomme dor\u00e9e)", "Les sorci\u00e8res en l\u00e2chent parfois \u00e0 leur mort (0-2 avec Butin III)"], faq: [{ question: "O\u00f9 trouver des champignons bruns facilement ?", answer: "Les champignons bruns poussent dans les zones sombres : grottes, sous les grands arbres, dans le Nether (en abondance sur les blocs de netherrack), dans les marais et dans le biome \u00eele aux champignons. Vous pouvez aussi les cultiver dans une pi\u00e8ce sombre (niveau de lumi\u00e8re 12 ou moins) avec de la terre ou du myc\u00e9lium." }, { question: "Peut-on acheter l'\u0153il d'araign\u00e9e ferment\u00e9 chez un villageois ?", answer: "Non, aucun villageois ne vend d'\u0153il d'araign\u00e9e ferment\u00e9. Vous devez le crafter vous-m\u00eame. Les sorci\u00e8res en l\u00e2chent parfois \u00e0 leur mort (drop rare). Les ingr\u00e9dients (\u0153il d'araign\u00e9e, sucre, champignon brun) sont tous facilement accessibles d\u00e8s le d\u00e9but de partie." }], relatedSlugs: ["carotte-doree", "pomme-doree", "faiblesse", "invisibilite", "metier-villageois"] } },
  { slug: "cochon-couronne", keyword: "cochon couronne minecraft", title: "Cochon Couronn\u00e9 Minecraft : Guide", h1: "Le Cochon Couronn\u00e9 dans Minecraft", metaDescription: "D\u00e9couvrez le cochon couronn\u00e9 Minecraft. Hommage permanent \u00e0 Technoblade sur l'\u00e9cran titre du jeu.", category: "mobs", volume: 210, content: { intro: "Le cochon couronn\u00e9 est un hommage permanent \u00e0 Technoblade (1999-2022), le c\u00e9l\u00e8bre YouTuber et joueur Minecraft d\u00e9c\u00e9d\u00e9 d'un cancer en juin 2022. Mojang a ajout\u00e9 un cochon portant une couronne sur l'\u00e9cran d'accueil de Minecraft. Les cochons normaux en jeu poss\u00e8dent 10 PV (5 c\u0153urs), spawnt dans les biomes herbeux et l\u00e2chent 1-3 c\u00f4tes de porc crues \u00e0 leur mort.", sections: [{ heading: "Hommage \u00e0 Technoblade", content: "Suite au d\u00e9c\u00e8s de Technoblade (Alex) en juin 2022, Mojang a rendu un hommage permanent en ajoutant un cochon portant une couronne sur l'\u00e9cran titre de Minecraft. Le personnage de Technoblade \u00e9tait iconiquement un cochon couronn\u00e9. Cet hommage est visible dans toutes les \u00e9ditions du jeu (Java et Bedrock) et restera permanent selon la confirmation de Mojang." }, { heading: "Le cochon dans le jeu normal", content: "Le cochon couronn\u00e9 n'est PAS un mob rencontrable en survie. Les cochons normaux dans le jeu ont ces statistiques : 10 PV (5 c\u0153urs), passifs, spawnt dans les biomes de plaines, for\u00eats et la plupart des biomes herbeux par groupes de 4. Drops : 1-3 c\u00f4tes de porc crues (1-3 c\u00f4tes cuites si tu\u00e9s par le feu). Ils sont reproductibles avec des carottes, des pommes de terre ou des betteraves." }, { heading: "Transformation par foudre", content: "Si la foudre frappe un cochon (naturellement ou via un trident avec Canalisation), il se transforme en piglin zombifi\u00e9. Le piglin zombifi\u00e9 poss\u00e8de 20 PV, est neutre (attaque seulement si provoqu\u00e9) et spawne avec une \u00e9p\u00e9e en or. C'est une des transformations les plus connues du jeu." }], tips: ["Le cochon couronn\u00e9 est visible uniquement sur l'\u00e9cran titre de Minecraft", "C'est un hommage permanent \u00e0 Technoblade (1999-2022)", "Les cochons normaux ont 10 PV et l\u00e2chent 1-3 c\u00f4tes de porc crues", "La foudre transforme un cochon en piglin zombifi\u00e9 (20 PV, neutre)", "Les cochons se reproduisent avec des carottes, pommes de terre ou betteraves"], faq: [{ question: "Peut-on trouver un cochon couronn\u00e9 en survie ?", answer: "Non, le cochon couronn\u00e9 n'existe que comme \u00e9l\u00e9ment visuel sur l'\u00e9cran titre du jeu. Les cochons normaux en survie ne portent pas de couronne et ne peuvent pas en recevoir. C'est un hommage purement visuel et non interactif." }, { question: "L'hommage est-il permanent ?", answer: "Oui, Mojang a officiellement confirm\u00e9 que le cochon couronn\u00e9 resterait sur l'\u00e9cran titre de Minecraft de mani\u00e8re permanente, en m\u00e9moire de Technoblade. Il est pr\u00e9sent dans les \u00e9ditions Java et Bedrock." }], relatedSlugs: ["golem-cuivre", "vache-champignon", "axolotl-bleu", "bonhomme-de-neige", "metier-villageois"] } },
  { slug: "ghast-desseche", keyword: "ghast dess\u00e9ch\u00e9 minecraft", title: "Ghast Minecraft : Guide Complet", h1: "Le Ghast dans Minecraft", metaDescription: "D\u00e9couvrez le ghast Minecraft. Ce mob hostile du Nether crache des boules de feu explosives. Guide de combat et drops.", category: "mobs", volume: 170, content: { intro: "Le ghast est un grand mob hostile flottant du Nether poss\u00e9dant seulement 10 PV (5 c\u0153urs) malgr\u00e9 sa taille imposante de 4\u00d74\u00d74 blocs. Il tire des boules de feu explosives \u00e0 longue port\u00e9e et sa larme de ghast est un ingr\u00e9dient essentiel pour les cristaux de l'End et la potion de r\u00e9g\u00e9n\u00e9ration. Apprendre \u00e0 renvoyer ses boules de feu est la technique de combat la plus efficace.", sections: [{ heading: "Caract\u00e9ristiques et statistiques", content: "Le ghast est une cr\u00e9ature flottante blanche de 4\u00d74\u00d74 blocs avec 9 tentacules. Malgr\u00e9 sa taille imposante, il n'a que 10 PV (5 c\u0153urs), ce qui le rend relativement fragile si vous pouvez le toucher. Il spawne dans le Nether dans les grands espaces ouverts avec au moins 5 blocs libres dans toutes les directions : plaines de lave (wastes), vall\u00e9es de sable des \u00e2mes et biome basaltes deltas. Son cri aigu est audible jusqu'\u00e0 100 blocs de distance." }, { heading: "Boules de feu et combat", content: "Le ghast tire des boules de feu explosives (puissance d'explosion 1). La technique principale est le renvoi : frappez la boule de feu avec n'importe quel projectile ou en m\u00eal\u00e9e (timing pr\u00e9cis). Une boule renvoy\u00e9e qui touche le ghast le tue instantan\u00e9ment. \u00c0 l'arc, Puissance V avec une fl\u00e8che suffit \u00e0 le tuer en un coup (10+ d\u00e9g\u00e2ts). D\u00e9g\u00e2ts des boules de feu en difficult\u00e9 Normale : 6 (incendie) + jusqu'\u00e0 17 (explosion selon la distance)." }, { heading: "Drops et utilisations", content: "Le ghast l\u00e2che \u00e0 sa mort : 0-2 poudre \u00e0 canon et 0-1 larme de ghast (augmentable avec Butin III : 0-4 de chaque). Il donne 5 XP. Les larmes de ghast ont deux utilisations cruciales : 1) Brasser une potion de r\u00e9g\u00e9n\u00e9ration (potion maladroite + larme de ghast = R\u00e9g\u00e9n\u00e9ration 45s). 2) Crafter un cristal de l'End (1 \u0153il de l'Ender + 1 larme de ghast + 7 verres), n\u00e9cessaire pour re-invoquer l'Ender Dragon." }, { heading: "Strat\u00e9gies avanc\u00e9es", content: "Les ghasts ne peuvent pas traverser les portails du Nether mais peuvent les d\u00e9sactiver avec leurs boules de feu. Prot\u00e9gez vos portails avec un abri en roche noire ou en pav\u00e9. En combat, gardez un arc avec Puissance V et des fl\u00e8ches en quantit\u00e9. L'armure en N\u00e9th\u00e9rite avec Protection IV r\u00e9duit significativement les d\u00e9g\u00e2ts. Les ghasts d\u00e9tectent les joueurs \u00e0 100 blocs de distance mais ne tirent qu'\u00e0 64 blocs." }], tips: ["Le ghast n'a que 10 PV (5 c\u0153urs) malgr\u00e9 sa taille de 4\u00d74\u00d74 blocs", "Renvoyez ses boules de feu pour le tuer en un seul coup", "Les larmes de ghast sont n\u00e9cessaires pour les cristaux de l'End et la R\u00e9g\u00e9n\u00e9ration", "L'arc Puissance V le tue en une fl\u00e8che (10+ d\u00e9g\u00e2ts)", "Il d\u00e9tecte \u00e0 100 blocs mais ne tire qu'\u00e0 64 blocs de distance"], faq: [{ question: "Comment renvoyer une boule de feu de ghast ?", answer: "Frappez la boule de feu en approche avec n'importe quel objet en m\u00eal\u00e9e (\u00e9p\u00e9e, main nue avec timing pr\u00e9cis) ou tirez dessus avec une fl\u00e8che, boule de neige ou \u0153uf. La boule renvoy\u00e9e inflige 1000 d\u00e9g\u00e2ts (bien au-del\u00e0 des 10 PV du ghast) si elle le touche. Le timing est plus facile avec une \u00e9p\u00e9e qu'\u00e0 main nue." }, { question: "Les larmes de ghast sont-elles rares ?", answer: "Les ghasts ne l\u00e2chent que 0-1 larme par kill naturellement. Avec Butin III, le drop monte \u00e0 0-4. Les ghasts \u00e9tant difficiles \u00e0 atteindre (vol \u00e0 haute altitude), les larmes sont effectivement rares. Conseil : construisez une plateforme dans le Nether \u00e0 la hauteur de vol des ghasts et utilisez un arc Puissance V pour les farmer efficacement." }], relatedSlugs: ["golem-cuivre", "vache-champignon", "cochon-couronne", "bonhomme-de-neige", "metier-villageois"] } }
];
